INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('ct_head', 'CT — Head', 'CT', 'multisite', 'adult', '{"examId":"ct","examTitle":"CT","siteLabel":"Head","inlineGuidance":"For suspected TIA within 7 days: completion of the BPAC TIA decision support tool is required to confirm CT Head appropriate. For first seizure, MRI is the preferred first-line investigation where available.","groups":[{"title":"Acute \u2014 within 48 hours","items":[{"type":"cb","id":"cth_a1","label":"Suspected TIA \u2014 within 7 days of episode, AND CT +/- CTA recommended by HNZ neurologist/stroke specialist OR BPAC TIA decision support tool indicates CT appropriate OR patient unable to access rapid specialist care","shortLabel":"Suspected TIA \u2014 within 7 days, meets criteria"},{"type":"cb","id":"cth_a2","label":"Focal neurological signs","shortLabel":"Focal neurological signs"},{"type":"cb","id":"cth_a3","label":"Seizure in a palliative care setting and result may change management","shortLabel":"Seizure in palliative care \u2014 result will change management"},{"type":"cb","id":"cth_a4","label":"Secondary care clinician or PCRL or radiologist advises referral for same or next day CT scan","shortLabel":"Advised by secondary care / PCRL / radiologist (same/next day)"}]},{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"cth_p2_1","label":"Change in pattern of headaches with progressive increase in frequency or severity (especially aged 50+) AND associated with chronic illness with potential cerebral complications (especially malignancy), OR exacerbated by coughing/sneezing/Valsalva (not typical migraine), OR associated with persistent nausea/vomiting (not typical migraine), OR objective neurological deficit","shortLabel":"Progressive/changing headache pattern (aged 50+) with concerning features"},{"type":"cb","id":"cth_p2_2","label":"Cognitive impairment with one or more features suggesting space-occupying lesion, bleed, or hydrocephalus: rapid cognitive decline over weeks; focal neurological signs; history of falls; anticoagulant therapy; gait ataxia or incontinence; history of cancers with propensity to brain metastases (lung, melanoma, breast)","shortLabel":"Cognitive impairment with features of SOL / bleed / hydrocephalus"},{"type":"cb","id":"cth_p2_3","label":"First seizure aged 21 years or older \u2014 clear history, patient low risk, OR MRI not available","shortLabel":"First seizure aged 21+, low risk or MRI unavailable"},{"type":"cb","id":"cth_p2_4","label":"Secondary care clinician or PCRL or radiologist advises referral for urgent CT scan","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)"}]},{"title":"P4 \u2014 Deferrable, within 6\u201312 weeks","items":[{"type":"cb","id":"cth_p4_1","label":"Cognitive impairment without features suggesting SOL, bleed, or hydrocephalus \u2014 and establishing the subtype diagnosis will alter management","shortLabel":"Cognitive impairment \u2014 subtype diagnosis will alter management"},{"type":"cb","id":"cth_p4_2","label":"Secondary care clinician or PCRL or radiologist advises referral for non-urgent CT scan","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)"}]}],"guidance":"Select the anatomical site(s) being requested, then complete the clinical indicators for each site. Review the National Community Referral Criteria for Imaging and HealthPathways before referring.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=15616.htm","guidanceNarrative":"For clinically suspected anterior circulation TIA events, if the patient is a potential candidate for carotid endarterectomy, carotid angiography (CTA) or if unavailable carotid ultrasound should be added to the CT head exam.","alternativeManagement":"Seizures with risk factors for intracranial pathology \u2014 seek Neurology phone advice. Poorly controlled or recurrent seizures \u2014 follow the appropriate pathway (Epilepsy in Adults, Epilepsy in Women, First Seizure in Adults, Seizure in Palliative Care HealthPathways).","notFundedDetail":"Established advanced dementia of more than 2 years duration, no unexpected change in disease progression and establishing the subtype will not alter management.","outOfCriteriaNote":"Established advanced dementia >2 years, no unexpected change, subtype will not alter management \u2014 not routinely funded. Seizures with risk factors for intracranial pathology \u2014 seek Neurology phone advice rather than CT.","footnotes":"*1 High risk features for TIA: less than 59 years old; ABCD2 greater than 4; crescendo TIAs; atrial fibrillation; on anticoagulants; severe or prolonged deficit (hemiparesis longer than 60 minutes); known carotid artery stenosis.\n*2 Features suggestive of underlying SOL, bleed, or hydrocephalus: rapid cognitive decline over weeks; presence of focal neurological signs; history of falls; anticoagulant therapy; gait ataxia or incontinence; history of cancers with propensity to brain metastases (lung, melanoma, breast).\n*3 Criteria for low-risk first seizure \u2014 all of the following must apply: single seizure which is unprovoked or provoked by a known substance; patient has since returned to normal health; none of the following risk factors for intracranial pathology apply: head injury, aged older than 40, fever/systemic symptoms, history of anticoagulation or malignancy, new focal neurologic deficit, focal seizure, persistent altered mental state, persistent headache.\n*4 Risk factors for intracranial pathology: head injury; aged older than 40; fever/systemic symptoms; history of anticoagulation or malignancy; new focal neurologic deficit; focal seizure; persistent altered mental state; persistent headache.","safetyQuestions":[{"type":"radio","id":"ct_metformin","label":"Is the patient on metformin?","options":["Yes","No","Unknown"]},{"type":"radio","id":"ct_contrast_allergy","label":"Known iodinated contrast allergy?","options":["Yes","No","Unknown"]}]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('ct_cap', 'CT — Chest/Abdomen/Pelvis', 'CT', 'multisite', 'adult', '{"examId":"ct","examTitle":"CT","siteLabel":"Chest/Abdomen/Pelvis","inlineGuidance":"Reserve for patients where after initial investigations the GP remains strongly suspicious of malignancy but no focal pathology or biopsy site is identified. Two or more persistently abnormal bloods (Hb, CRP, Ca, ALP) significantly increases probability of cancer.","groups":[{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"ctcap_1","label":"Male >50 or female >60 with strong suspicion of malignancy, no focal pathology, AND unintentional unexplained weight loss >5% over 3\u20136 months (+/- abdominal pain, fatigue, nausea)","shortLabel":"Male >50 / female >60, unexplained weight loss >5%, strong malignancy suspicion"},{"type":"cb","id":"ctcap_2","label":"Male >40 or female >50 with strong suspicion of malignancy, no focal pathology, AND weight loss >5% over 3\u20136 months AND 2+ of: raised CRP, low Hb, raised Ca, high platelets, high ALP, low albumin \u2014 persistent on repeat after 3 weeks","shortLabel":"Male >40 / female >50, weight loss >5%, 2+ abnormal bloods persisting"},{"type":"cb","id":"ctcap_3","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent CT Chest, Abdomen and Pelvis","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)"}]}],"guidance":"Select the anatomical site(s) being requested, then complete the clinical indicators for each site. Review the National Community Referral Criteria for Imaging and HealthPathways before referring.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=17650.htm","guidanceNarrative":"This pathway covers patients with nonspecific symptoms where the GP suspects underlying primary or secondary malignancy in the abdomen or pelvis, with no localising features or mass for tissue sampling evident on examination or initial investigations. The presence of two or more persistently abnormal blood test results (Hb, CRP, Ca, ALP) significantly increases the probability of cancer being diagnosed. CT CAP should be reserved for patients where after initial investigations and review the GP remains strongly suspicious of underlying malignancy. For presentations with nonspecific symptoms and abnormal lab results not meeting criteria, discussion with PCRL or secondary care specialist or radiologist for consideration of CT imaging is recommended.","alternativeManagement":"Not indicated where: patient has a current cancer diagnosis and is under continued follow-up; patient has been investigated by secondary care within the last 12 months for the same symptoms/signs; presentation requires urgent admission or urgent secondary care assessment; localising clinical features or results from preliminary investigations suggest cancer in a specific system; recent ultrasound of abdomen and pelvis within the last three months (seek advice from radiologist or secondary care specialist); CT Chest, Abdomen and Pelvis within the last 12 months (seek advice from radiologist or secondary care specialist).","notFundedDetail":"Patient is unfit for treatment or unwilling to have further investigations and/or treatment.","outOfCriteriaNote":"Not indicated where: current cancer under follow-up; investigated by secondary care within 12 months for same symptoms; localising features on initial investigations; recent USS abdomen/pelvis within 3 months; CT CAP within 12 months.","footnotes":"","safetyQuestions":[{"type":"radio","id":"ct_metformin","label":"Is the patient on metformin?","options":["Yes","No","Unknown"]},{"type":"radio","id":"ct_contrast_allergy","label":"Known iodinated contrast allergy?","options":["Yes","No","Unknown"]}]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('ct_chest', 'CT — Chest', 'CT', 'multisite', 'adult', '{"examId":"ct","examTitle":"CT","siteLabel":"Chest","inlineGuidance":"Urgent CXR (same or next day) remains the initial investigation where lung cancer is suspected. CT Chest is a subsequent step. A normal CXR does not exclude lung cancer (sensitivity ~75\u201380%).","groups":[{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"ctc_p2_1","label":"Unexplained haemoptysis (in absence of chest infection, upper respiratory tract causes excluded) AND investigations including CXR fail to identify a cause","shortLabel":"Unexplained haemoptysis \u2014 CXR negative, no infection"},{"type":"cb","id":"ctc_p2_2","label":"Aged over 55 years, current smoker, AND one or more new onset concerning symptoms for lung cancer persistent for 6 weeks despite appropriate treatment AND unexplained despite CXR and bloods","shortLabel":"Smoker >55, new lung cancer symptoms >6 weeks, CXR/bloods inconclusive"},{"type":"cb","id":"ctc_p2_3","label":"Indeterminate abnormality on CXR raising possibility of lung cancer (e.g. bulky hilum) AND CT chest recommended in radiology report","shortLabel":"Indeterminate CXR abnormality \u2014 CT recommended in report"},{"type":"cb","id":"ctc_p2_4","label":"Persistent consolidation on 6-week follow-up CXR AND CT chest recommended in radiology report","shortLabel":"Persistent consolidation on 6-week CXR \u2014 CT recommended in report"},{"type":"cb","id":"ctc_p2_5","label":"Secondary care clinician or radiologist advises urgent staging CT chest/liver for suspicious lesion on CXR AND CT is advised next step on local HealthPathway","shortLabel":"Staging CT advised by secondary care for suspicious CXR lesion"},{"type":"cb","id":"ctc_p2_6","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent CT chest","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)"}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"ctc_p3_1","label":"Isolated pulmonary nodule identified on CXR, cannot be confirmed as benign from x-ray appearances alone, AND referral for CT chest recommended in radiology report","shortLabel":"Isolated pulmonary nodule on CXR \u2014 CT recommended in report"},{"type":"cb","id":"ctc_p3_2","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent CT chest","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)"}]}],"guidance":"Select the anatomical site(s) being requested, then complete the clinical indicators for each site. Review the National Community Referral Criteria for Imaging and HealthPathways before referring.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=448214.htm","guidanceNarrative":"A diagnosis of lung cancer and initiating imaging investigations should be considered for all patients with concerning symptoms or signs lasting more than 3 weeks, or sooner if the patient has risk factors for lung cancer. Patients who identify as M\u0101ori have higher rates of lung cancer than non-M\u0101ori and a lower threshold for investigating concerning symptoms or signs should be considered especially if the patient has risk factors. Urgent CXR (same or next day) remains the initial investigation of choice for symptomatic patients where lung cancer is suspected. Studies suggest the sensitivity of a CXR is around 75-80%, highlighting the importance of safety netting for symptomatic patients with a normal CXR. The presence of multiple signs and symptoms, particularly in combination with haemoptysis, weight loss or persistent thrombocytosis, has a significantly stronger positive predictive value for lung cancer. Regarding CT after normal CXR: it is not yet clear how or when to select patients for CT in the presence of a normal CXR due to the low predictive value of symptoms. The overall incidence of lung cancer amongst CXR referrals is approximately 1.4%. Studies show the risk can be stratified using patient age and smoking status \u2014 current-smokers aged over 55 years are proposed as the threshold for CT after normal CXR.","alternativeManagement":"Patient re-presents with concerning symptoms and CXR is normal but doesn''t meet CT criteria \u2014 seek advice from secondary care respiratory team regarding appropriate management and whether CT chest is warranted. Persistent non-specific non-localising symptoms concerning for underlying cancer (e.g. weight loss, fatigue) and initial investigations including CXR and bloods fail to identify a cause \u2014 see CT Chest/Abdomen/Pelvis HealthPathway. Initial presentation with respiratory symptoms or signs concerning for lung cancer \u2014 refer for urgent CXR as the initial investigation. Follow-up of nodule discovered incidentally on CT chest scan \u2014 refer to secondary care for management advice unless radiology report confirms benign.","notFundedDetail":"","outOfCriteriaNote":"Initial presentation with respiratory symptoms: refer for urgent CXR first. Re-presentation with normal CXR but not meeting CT criteria: seek advice from secondary care respiratory team.","footnotes":"*1 Concerning symptoms and signs for lung cancer: unexplained new or worsening dyspnoea; unexplained cough persisting and worsening for more than 3 weeks; unexplained chest and/or shoulder pain persisting for more than 3 weeks; unexplained changes in existing symptoms in patients with underlying chronic respiratory problems persisting for more than 3 weeks; unexplained hoarseness persisting for more than 3 weeks; recurrent or unresolved chest infections; persistent unexplained haemoptysis in the absence of red flags; unexplained weight loss and loss of appetite persisting for more than 3 weeks; unexplained abnormal chest signs persisting more than 3 weeks; new supraclavicular lymphadenopathy; new cervical lymphadenopathy persisting more than 3 weeks where nodes are greater than 1cm in a patient with other lung cancer symptoms/signs/risk factors; features suggestive of paraneoplastic syndromes.\n*2 Risk factors for lung cancer: current or past smoker (increased risk with duration and quantity; reduced risk with duration since quitting especially more than 15 years); family history of lung cancer in sibling; personal history of cancer especially head and neck cancer; history of lung disease including COPD, cystic fibrosis; exposure to asbestos, radon, air pollutants.\n*3 Safety netting after normal CXR: with sensitivity of CXR for lung cancer reported as 75-80%, a normal CXR may provide false reassurance. Safety netting is a diagnostic management strategy to ensure patients are monitored until symptoms are explained or resolved. Persistent or worsening unexplained respiratory symptoms, especially clusters of symptoms and especially in patients at increased risk of lung cancer, warrant further investigation despite a normal CXR by way of referral for CT or discussion with a secondary care clinician or PCRL.\n*4 Local pathways \u2014 direct to PET-CT: where CXR findings are suspicious for lung cancer but no features suggest it is not curable, the preferred next step in some districts is to proceed directly with whole body PET-CT rather than CT chest.","safetyQuestions":[{"type":"radio","id":"ct_metformin","label":"Is the patient on metformin?","options":["Yes","No","Unknown"]},{"type":"radio","id":"ct_contrast_allergy","label":"Known iodinated contrast allergy?","options":["Yes","No","Unknown"]}]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('ct_colonography', 'CT — Colonography (CTC)', 'CT', 'multisite', 'adult', '{"examId":"ct","examTitle":"CT","siteLabel":"Colonography (CTC)","inlineGuidance":"CTC may be appropriate where the patient is over 80, has co-morbidities making colonoscopy higher risk, has an abdominal mass, or following failed/incomplete colonoscopy. All referrals should go via secondary care single point of entry for triage to colonoscopy or CTC.","groups":[{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"ctc_col_p2_1","label":"Altered bowel habit (looser and/or more frequent) >6 weeks PLUS unexplained rectal bleeding (benign anal causes treated or excluded), aged >50 years","shortLabel":"Altered bowel habit >6 wks + rectal bleeding, aged >50"},{"type":"cb","id":"ctc_col_p2_2","label":"Unexplained rectal bleeding (benign anal causes treated or excluded) WITH iron deficiency anaemia (Hb below reference range AND low ferritin)","shortLabel":"Rectal bleeding + iron deficiency anaemia"},{"type":"cb","id":"ctc_col_p2_3","label":"Known or suspected colorectal cancer (on imaging, palpable, or visible on rectal examination) \u2014 for pre-operative procedure to rule out synchronous pathology","shortLabel":"Known/suspected CRC \u2014 pre-operative synchronous pathology exclusion"},{"type":"cb","id":"ctc_col_p2_4","label":"Secondary care clinician or radiologist advises referral for urgent CTC","shortLabel":"Advised by secondary care / radiologist (urgent)"}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"ctc_col_p3_1","label":"Altered bowel habit (looser and/or more frequent) >6 weeks, aged 50 years or older","shortLabel":"Altered bowel habit >6 wks, aged 50+"},{"type":"cb","id":"ctc_col_p3_2","label":"Altered bowel habit >6 weeks PLUS unexplained rectal bleeding (benign anal causes treated or excluded), aged 40-50 years","shortLabel":"Altered bowel habit >6 wks + rectal bleeding, aged 40-50"},{"type":"cb","id":"ctc_col_p3_3","label":"Unexplained rectal bleeding (benign anal causes treated or excluded), aged 50 years or older","shortLabel":"Rectal bleeding, aged 50+"},{"type":"cb","id":"ctc_col_p3_4","label":"Unexplained iron deficiency anaemia (Hb below local reference range AND low ferritin)","shortLabel":"Unexplained iron deficiency anaemia"},{"type":"cb","id":"ctc_col_p3_5","label":"NZGG Category 2 family history PLUS altered bowel habit >6 weeks PLUS unexplained rectal bleeding, aged 40 years or older","shortLabel":"NZGG Cat 2 family history + bowel symptoms, aged 40+"},{"type":"cb","id":"ctc_col_p3_6","label":"NZGG Category 3 family history PLUS altered bowel habit >6 weeks PLUS unexplained rectal bleeding, aged 25 years or older","shortLabel":"NZGG Cat 3 family history + bowel symptoms, aged 25+"},{"type":"cb","id":"ctc_col_p3_7","label":"Secondary care clinician or radiologist advises referral for non-urgent CTC","shortLabel":"Advised by secondary care / radiologist (non-urgent)"}]}],"guidance":"Select the anatomical site(s) being requested, then complete the clinical indicators for each site. Review the National Community Referral Criteria for Imaging and HealthPathways before referring.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=53111.htm","guidanceNarrative":"The Ministry of Health and Bowel Cancer Working Group recommendation is for all referrals for investigation of bowel symptoms meeting the direct access referral criteria to be referred to secondary care via a single point of entry and triaged to either colonoscopy or CT colonography (CTC). CTC may be appropriate where the patient is over 80 years, has significant co-morbidities where colonoscopy presents higher risk (e.g. respiratory risk from sedation), has an abdominal mass on examination, or following failed or incomplete colonoscopy. CTC is of comparable sensitivity to colonoscopy for the detection of clinically significant polyps and tumours. All referrals require: ability to tolerate bowel prep and the procedure and possible further treatment, and no previous colonoscopy or CTC within the last 5 years unless there is a clear indication to repeat.","alternativeManagement":"Rectal bleeding aged less than 50 years (normal haemoglobin) \u2014 consider secondary care referral for assessment and possible flexible sigmoidoscopy.","notFundedDetail":"Acute diarrhoea for less than six weeks duration where it most likely has an infectious aetiology. Irritable bowel syndrome. Constipation as a single symptom. Uncomplicated CT-proven diverticulitis without suspicious radiological features. Abdominal pain alone without P3 six-week category features. Low ferritin with normal haemoglobin in a patient aged younger than 50 years.","outOfCriteriaNote":"Not indicated for: acute diarrhoea <6 weeks (likely infectious); IBS; constipation as single symptom; uncomplicated CT-proven diverticulitis; abdominal pain alone; low ferritin with normal Hb aged <50. All criteria require ability to tolerate bowel prep AND no colonoscopy/CTC within last 5 years (unless clear indication).","footnotes":"*1 NZGG family history categories:\nCategory 2 (moderately increased familial risk): one first-degree relative diagnosed with CRC under age 55, OR two first-degree relatives on the same side of the family with CRC at any age.\nCategory 3 (potentially high risk): family history of FAP, Lynch syndrome or other familial CRC syndromes; one first-degree relative plus two or more first- or second-degree relatives all on the same side with CRC at any age; two first-degree relatives or one first-degree relative plus one or more second-degree relatives all on the same side with CRC, and one such relative was diagnosed under age 54, or developed two or more bowel cancers, or developed an extracolonic tumour suggestive of Lynch syndrome (endometrial, ovarian, stomach, small bowel, renal pelvis, pancreas or brain); a first-degree relative with CRC diagnosed under age 50 where tumour immunohistochemistry has revealed loss of protein expression for one of the mismatch repair genes.","safetyQuestions":[{"type":"radio","id":"ct_metformin","label":"Is the patient on metformin?","options":["Yes","No","Unknown"]},{"type":"radio","id":"ct_contrast_allergy","label":"Known iodinated contrast allergy?","options":["Yes","No","Unknown"]}]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('ct_ivu', 'CT — IVU / CT Renal', 'CT', 'multisite', 'adult', '{"examId":"ct","examTitle":"CT","siteLabel":"IVU / CT Renal","inlineGuidance":"CT IVU is preferred for renal masses, painless haematuria, and obstruction. Contraindicated if eGFR <30 or iodinated contrast allergy \u2014 use renal ultrasound instead. CT KUB is a separate non-contrast scan for stone detection.","groups":[{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"ctivu_p2_1","label":"Macroscopic haematuria where UTI excluded (or persists after treating UTI) AND patient aged 40-85 years","shortLabel":"Macroscopic haematuria, UTI excluded, aged 40-85"},{"type":"cb","id":"ctivu_p2_2","label":"Macroscopic haematuria where UTI excluded AND patient aged under 40, initial investigations including renal ultrasound normal, and haematuria persists","shortLabel":"Macroscopic haematuria, aged <40, renal US normal, persists"},{"type":"cb","id":"ctivu_p2_3","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent CT IVU or CT Renal scan","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)"}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"ctivu_p3_1","label":"CT IVU recommended by secondary care specialist for unexplained asymptomatic microscopic haematuria after initial investigations including renal tract ultrasound fail to identify a cause","shortLabel":"Asymptomatic microscopic haematuria \u2014 CT IVU recommended by secondary care"},{"type":"cb","id":"ctivu_p3_2","label":"Multiphase renal CT recommended by secondary care specialist or radiology report for incidental finding on ultrasound: solid lesion >1cm OR complex cyst (Bosniak IIF, III, or IV)","shortLabel":"Incidental solid lesion >1cm or complex Bosniak cyst on US \u2014 CT recommended"},{"type":"cb","id":"ctivu_p3_3","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent CT IVU or CT Renal scan","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)"}]}],"guidance":"Select the anatomical site(s) being requested, then complete the clinical indicators for each site. Review the National Community Referral Criteria for Imaging and HealthPathways before referring.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=177141.htm","guidanceNarrative":"CT IVU (also known as CT Urogram) is the best imaging investigation for renal masses, investigating painless haematuria, and causes of obstruction, but this is at the expense of increased radiation dose and the need for intravenous contrast. Images are obtained in 2 or 3 phases to image the kidneys in the nephrogenic phase and ureters and bladder in excretory phases. CT IVU together with cystoscopy should be used for older patients (40 years or older) with painless haematuria and in younger patients (less than 40 years) when initial investigations including ultrasound and cystoscopy are abnormal or if haematuria persists. CT IVU uses a high dose of iodine contrast media which can be nephrotoxic. CT IVU is not recommended for patients with reduced renal function (eGFR lower than 30) or with known allergy to iodinated contrast \u2014 renal ultrasound is the recommended investigation in these patient groups. CT KUB is a different non-contrast scan, primarily for detection and monitoring of stones.","alternativeManagement":"","notFundedDetail":"","outOfCriteriaNote":"","footnotes":"","safetyQuestions":[{"type":"radio","id":"ct_metformin","label":"Is the patient on metformin?","options":["Yes","No","Unknown"]},{"type":"radio","id":"ct_contrast_allergy","label":"Known iodinated contrast allergy?","options":["Yes","No","Unknown"]}]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('ct_kub', 'CT — KUB', 'CT', 'multisite', 'adult', '{"examId":"ct","examTitle":"CT","siteLabel":"KUB","inlineGuidance":"For pregnant patients or females <35 without haematuria, fever, history of stones, or solitary kidney: request renal tract ultrasound instead. Consider plain X-ray KUB at same time. Avoid repeated CT KUB in otherwise healthy patients aged <50 with known stones and typical presentation without red flags.","groups":[{"title":"Refer for acute assessment \u2014 red flags (admit, do not image)","items":[{"type":"cb","id":"kub_acute_1","label":"Creatinine >160 mmol/L or eGFR <45 ml/min","shortLabel":"Creatinine >160 or eGFR <45"},{"type":"cb","id":"kub_acute_2","label":"Solitary kidney","shortLabel":"Solitary kidney"},{"type":"cb","id":"kub_acute_3","label":"Temperature above 38 degrees","shortLabel":"Temp >38\u00b0C"},{"type":"cb","id":"kub_acute_4","label":"Peritonitis / signs of sepsis","shortLabel":"Peritonitis / sepsis"},{"type":"cb","id":"kub_acute_5","label":"Known bilateral ureteric stones","shortLabel":"Bilateral ureteric stones"}]},{"title":"Acute \u2014 within 48 hours (no red flags)","items":[{"type":"cb","id":"kub_48_1","label":"First presentation of suspected renal colic with no red flags","shortLabel":"First presentation renal colic, no red flags"},{"type":"cb","id":"kub_48_2","label":"Secondary care clinician, PCRL or radiologist advises referral for same or next day CT KUB","shortLabel":"Advised by secondary care / PCRL / radiologist (same/next day)"}]},{"title":"S2 \u2014 Specified date, within 2 weeks of target date","items":[{"type":"cb","id":"kub_s2_1","label":"Follow-up per Renal Colic and Urinary Tract Stones HealthPathway, if calculus not visible on KUB X-ray","shortLabel":"Follow-up \u2014 calculus not visible on KUB X-ray"},{"type":"cb","id":"kub_s2_2","label":"Secondary care clinician, PCRL or radiologist advises referral for specified-date CT KUB","shortLabel":"Advised by secondary care / PCRL / radiologist (specified date)"}]}],"guidance":"Select the anatomical site(s) being requested, then complete the clinical indicators for each site. Review the National Community Referral Criteria for Imaging and HealthPathways before referring.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=20717.htm","guidanceNarrative":"For pregnant patients or females younger than 35 without haematuria, fever, history of stones, or solitary kidney, request renal tract ultrasound instead of CT KUB. Consider arranging additional plain X-ray KUB at the same time \u2014 confirming the stone is visible on x-ray at presentation enables 4-week follow-up with plain x-ray if required. Avoid requesting repeated CT KUB imaging in otherwise healthy patients aged younger than 50 years with a known history of kidney stones; if typical presentation without red flags, repeat imaging is not usually required.","alternativeManagement":"Females aged younger than 35 years with renal colic \u2014 arrange renal ultrasound rather than CT KUB, unless the patient has: haematuria x10, fever, history of stones, or solitary kidney. Pregnant women with renal colic \u2014 arrange renal ultrasound.","notFundedDetail":"Recurrent renal colic \u2014 imaging is not required if pain is well controlled and the patient is aged younger than 50 years, presenting with typical renal colic, has no red flags, and has had a confirmed stone on CT KUB during the last 5 years. Surveillance of asymptomatic patients with previous nephrolithiasis. Children younger than 16 years \u2014 consider requesting paediatric assessment.","outOfCriteriaNote":"Not routinely funded for: recurrent renal colic in patients aged <50 with typical presentation, no red flags, and confirmed stone on CT KUB in last 5 years; surveillance of asymptomatic patients with previous nephrolithiasis; children younger than 16 years.","footnotes":"*1 Renal colic red flags: fever/rigors; single kidney; known significant renal impairment; suspected bilateral obstructing stones; pregnancy.","safetyQuestions":[{"type":"radio","id":"ct_metformin","label":"Is the patient on metformin?","options":["Yes","No","Unknown"]},{"type":"radio","id":"ct_contrast_allergy","label":"Known iodinated contrast allergy?","options":["Yes","No","Unknown"]}]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('ct_sinus', 'CT — Sinus', 'CT', 'multisite', 'adult', '{"examId":"ct","examTitle":"CT","siteLabel":"Sinus","inlineGuidance":"CRS symptoms are poor predictors of sinus disease on imaging (specificity ~30%). Early CT sinus is more cost-efficient than presuming CRS on symptoms alone. All prerequisites below must be met.","groups":[{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"sin_p3_1","label":"Suspected chronic rhinosinusitis AND moderate to severe symptoms persist despite daily nasal saline irrigation AND intranasal corticosteroids (INCS) trialled for at least 12 weeks with satisfactory patient technique and compliance AND patient has not previously had a CT sinus scan","shortLabel":"Chronic rhinosinusitis \u2014 failed 12-week INCS trial, no prior CT sinus","mandatory":true},{"type":"cb","id":"sin_p3_2","label":"ORL specialist, PCRL or radiologist advises referral for non-urgent CT sinus","shortLabel":"Advised by ORL / PCRL / radiologist (non-urgent)"}]}],"guidance":"Select the anatomical site(s) being requested, then complete the clinical indicators for each site. Review the National Community Referral Criteria for Imaging and HealthPathways before referring.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=29072.htm","guidanceNarrative":"Chronic Rhinosinusitis (CRS) symptoms and its clinical presentation to primary care have been shown to be poor predictors of sinus disease on imaging with a low specificity of approximately 30%. Early CT sinus to confirm the diagnosis has been shown to be both beneficial to the patient and more cost-efficient than presuming a diagnosis of CRS based on symptoms alone. Rhinosinusitis is one of the most common reasons for adult outpatient antibiotic prescriptions, though there is little clinical evidence to support this practice especially for chronic rhinosinusitis. These national CT sinus referral pre-requisites are necessarily based on a compromise between specialist advice and Health New Zealand funded resource availability. Refer for acute assessment without imaging if rhinosinusitis symptoms are associated with any red flags for intracranial or orbital pathology including: severe frontal headache, severe systemic symptoms, altered visual acuity or diplopia.","alternativeManagement":"Rhinosinusitis symptoms associated with any of the following red flags for sino-nasal malignancy \u2014 refer for urgent ORL assessment: unilateral nasal obstruction with haemo-serous discharge; recent onset of Horner syndrome, diplopia, or cranial neuropathies (particularly sensory change); paraesthesia in the skin of cheek, maxillary gingiva, or hard palate. Allergic rhinitis causing nasal obstruction or discharge \u2014 see local Rhino-Sinusitis HealthPathway.","notFundedDetail":"Follow-up scans to assess treatment response.","outOfCriteriaNote":"Not routinely funded for follow-up scans to assess treatment response. Red flags for sino-nasal malignancy (unilateral nasal obstruction with haemo-serous discharge; Horner syndrome/diplopia/cranial neuropathies; paraesthesia of cheek/gingiva/palate) \u2014 refer urgently to ORL.","footnotes":"","safetyQuestions":[{"type":"radio","id":"ct_metformin","label":"Is the patient on metformin?","options":["Yes","No","Unknown"]},{"type":"radio","id":"ct_contrast_allergy","label":"Known iodinated contrast allergy?","options":["Yes","No","Unknown"]}]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('us_abdomen', 'Ultrasound — Abdomen', 'Ultrasound', 'multisite', 'adult', '{"examId":"us","examTitle":"Ultrasound","siteLabel":"Abdomen","inlineGuidance":"Opportunistic liver function testing is not indicated for asymptomatic people without risk factors.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","items":[{"type":"cb","id":"usa_emerg_1","label":"Suspected acute cholecystitis or cholangitis (intractable biliary colic not relieved by simple analgesia, especially with fever or persistent vomiting)","shortLabel":"Suspected acute cholecystitis/cholangitis"},{"type":"cb","id":"usa_emerg_2","label":"Acute abdomen, including possible appendicitis","shortLabel":"Acute abdomen / possible appendicitis"},{"type":"cb","id":"usa_emerg_3","label":"Suspicion of ruptured abdominal aortic aneurysm","shortLabel":"Suspected ruptured AAA"},{"type":"cb","id":"usa_emerg_4","label":"Suspected testicular torsion","shortLabel":"Suspected testicular torsion"}]},{"title":"Acute \u2014 within 48 hours","items":[{"type":"cb","id":"usa_48_1","label":"Painful jaundice","shortLabel":"Painful jaundice"},{"type":"cb","id":"usa_48_2","label":"Painless jaundice without obvious cause (consider discussing with secondary care or PCRL \u2014 CT may be more appropriate)","shortLabel":"Painless jaundice \u2014 consider PCRL advice re CT"},{"type":"cb","id":"usa_48_3","label":"Secondary care clinician, PCRL or radiologist advises referral for same or next day ultrasound scan","shortLabel":"Advised by secondary care / PCRL / radiologist (same/next day)"}]},{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"usa_p2_1","label":"Obstructive picture on liver function testing: elevated ALP more than 2x ULN together with elevated GGT +/- raised bilirubin +/- raised ALT","shortLabel":"Obstructive LFTs: ALP >2x ULN + elevated GGT"},{"type":"cb","id":"usa_p2_2","label":"Suspected acute cholecystitis/biliary colic with raised ALP and GGT +/- bilirubin AND symptoms settle with analgesia AND biliary tree has not previously been imaged","shortLabel":"Biliary colic with raised ALP/GGT \u2014 biliary tree not previously imaged"},{"type":"cb","id":"usa_p2_3","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent ultrasound scan","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)"}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"usa_p3_1","label":"Recurrent right upper quadrant or epigastric non-dyspepsia pain without previous imaging","shortLabel":"Recurrent RUQ/epigastric pain, no prior imaging"},{"type":"cb","id":"usa_p3_2","label":"Suspected resolved acute biliary colic or cholecystitis, without previous imaging showing gallstones, AND patient is a potential candidate for and would accept cholecystectomy","shortLabel":"Resolved biliary colic/cholecystitis, no prior imaging, surgical candidate"},{"type":"cb","id":"usa_p3_3","label":"ALP greater than 2x ULN AND elevated GGT confirming liver origin AND elevated ALP persists on re-testing after 3 months","shortLabel":"ALP >2x ULN + elevated GGT, persists after 3 months"},{"type":"cb","id":"usa_p3_4","label":"ALT greater than 120 IU/L AND conservative methods unsuccessful in patients with high risk factors (diabetes, obesity, hepatotoxic medications) AND no clinical features of concern","shortLabel":"ALT >120 IU/L, conservative measures failed, high risk factors"},{"type":"cb","id":"usa_p3_5","label":"Isolated raised GGT more than 5x ULN and persists on re-testing after 3 months","shortLabel":"Isolated GGT >5x ULN, persists after 3 months"},{"type":"cb","id":"usa_p3_6","label":"Asymptomatic newly suspected abdominal aortic aneurysm (e.g. on clinical examination or other imaging)","shortLabel":"Newly suspected AAA \u2014 asymptomatic"},{"type":"cb","id":"usa_p3_7","label":"Non-pulsatile abdominal mass and suspected enlarged liver on examination","shortLabel":"Non-pulsatile abdominal mass / suspected hepatomegaly"},{"type":"cb","id":"usa_p3_8","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent ultrasound scan","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)"}]},{"title":"S3 \u2014 Specified date, within 6 weeks of target date","items":[{"type":"cb","id":"usa_s3_1","label":"HCC surveillance using liver ultrasound as initially recommended by a gastroenterologist or other secondary care specialist, or as recommended by an agreed local pathway","shortLabel":"HCC surveillance \u2014 specialist recommended"},{"type":"cb","id":"usa_s3_2","label":"Surveillance of known abdominal aortic aneurysm according to local HealthPathway or NZ Vascular Society guidelines (2015) or secondary care specialist advice","shortLabel":"Known AAA surveillance per HealthPathway or NZ Vascular Society guidelines"},{"type":"cb","id":"usa_s3_3","label":"Follow-up of incidental finding on imaging (including gallbladder polyps) according to Incidental Findings on Imaging HealthPathway or radiology report/PCRL advice","shortLabel":"Incidental finding follow-up per HealthPathway or radiology report"}]}],"guidance":"Select the anatomical site being requested, then complete the clinical indicators. Note: maternity and gynaecological ultrasound is outside CRR scope \u2014 refer via separate pathway.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=15607.htm","guidanceNarrative":"Opportunistic liver function testing is not indicated for asymptomatic people without risk factors. 2.5% of the normal population will fall outside the upper limit of the reference range as part of normal statistical distribution, and test results may fluctuate as a physiological response. Elevated liver enzyme levels are estimated to occur in up to 9% of asymptomatic people. Abnormal liver blood test results should only be interpreted after review of previous results, past medical history and current medical condition. Liver disease is rare among people with abnormal LFT results in primary care. On the other hand, severe liver disease may be present with little or no liver function abnormality, so the level or duration of elevation should not determine the significance, but the result should be viewed within the context of trend, past medical and drug history and current symptoms. For practical purposes, marker abnormalities are usually considered ''borderline'' if they are less than 2 times the ULN and ''mild'' if they are 2-5 times the ULN. If hepatocellular injury is suspected and the patient does not have concerning symptoms/features, ultrasound is a second-tier investigation after investigating the most likely causes. Obesity and raised ALT provide strong evidence for a presumptive diagnosis of fatty liver \u2014 ultrasound is not always necessary. Ultrasound imaging is a first-line investigation if cholestasis is suspected based on LFT results.","alternativeManagement":"Upper abdominal non-pulsatile mass not consistent with hepatomegaly \u2014 discuss with PCRL or relevant secondary care specialist as referral for CT abdomen may be more appropriate. Unexplained weight loss, persistent fatigue, vague abdominal pain and suspicion of underlying malignancy \u2014 see local CT Chest, Abdomen and Pelvis HealthPathway.","notFundedDetail":"Hernia in adults. Infective hepatitis. Follow-up imaging of previously diagnosed gallstones in asymptomatic patients. Isolated bloating (however with additional clinical symptoms such as loss of appetite, weight loss, abdominal pain or abnormal vaginal bleeding, USS or CT may be warranted). Follow-up imaging of simple renal or hepatic cysts. Screening for aortic aneurysm or fatty liver.","outOfCriteriaNote":"Not routinely funded for: hernia in adults; infective hepatitis; follow-up of previously diagnosed gallstones in asymptomatic patients; isolated bloating; follow-up of simple renal or hepatic cysts; screening for AAA or fatty liver.","footnotes":"","safetyQuestions":[]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('us_carotid', 'Ultrasound — Carotid', 'Ultrasound', 'multisite', 'adult', '{"examId":"us","examTitle":"Ultrasound","siteLabel":"Carotid","inlineGuidance":"All patients with suspected TIA who after specialist assessment are candidates for carotid endarterectomy should have urgent carotid imaging. Choice of modality (US, CTA, or MRA) based on local expertise. Carotid imaging preferably completed at same visit as brain imaging.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","items":[{"type":"cb","id":"usc_emerg_1","label":"Suspected TIA with any of: atypical symptoms; currently on anticoagulants; new or known atrial fibrillation","shortLabel":"Suspected TIA with atypical symptoms, anticoagulants, or AF"}]},{"title":"Acute \u2014 within 48 hours","items":[{"type":"cb","id":"usc_48_1","label":"Suspected TIA with typical symptoms, not in AF, not on anticoagulants AND episode within last 2 weeks AND symptoms consistent with anterior circulation TIA (language dysfunction and/or limb weakness) AND patient is a candidate for carotid endarterectomy AND acute stroke specialist not available AND carotid imaging recommended by HNZ neurologist/stroke specialist OR BPAC TIA tool indicates carotid imaging appropriate","shortLabel":"Suspected anterior circulation TIA \u2014 meets carotid imaging criteria"}]}],"guidance":"Select the anatomical site being requested, then complete the clinical indicators. Note: maternity and gynaecological ultrasound is outside CRR scope \u2014 refer via separate pathway.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=29069.htm","guidanceNarrative":"Recommended best practice is for all patients with suspected TIA who after specialist assessment are considered as candidates for carotid endarterectomy to have urgent carotid imaging. The choice of modality (ultrasound, CTA, or MRA) should be based on local expertise and availability. Carotid imaging is preferably completed at the same visit as brain imaging.","alternativeManagement":"High-risk TIAs (atypical symptoms, patient in atrial fibrillation and on anticoagulants) \u2014 request acute on-call stroke specialist assessment. Suspected TIA over 7 days ago \u2014 see local TIA HealthPathway.","notFundedDetail":"Carotid endarterectomy is not publicly funded for asymptomatic stenosis so carotid imaging is not funded for: asymptomatic bruits; carotid artery calcification on X-ray; screening tests.","outOfCriteriaNote":"Not funded for: asymptomatic bruits; carotid artery calcification on X-ray; screening tests. High risk TIAs (atypical symptoms, AF, anticoagulants) \u2014 request acute on-call stroke specialist assessment.","footnotes":"","safetyQuestions":[]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('us_dvt', 'Ultrasound — DVT', 'Ultrasound', 'multisite', 'adult', '{"examId":"us","examTitle":"Ultrasound","siteLabel":"DVT","inlineGuidance":"Use Well''s score to stratify clinical suspicion. D-dimer should be used in conjunction with Well''s score.","groups":[{"title":"Acute \u2014 within 24 hours","items":[{"type":"cb","id":"usd_24_1","label":"Superficial venous thrombosis affecting the proximal long saphenous vein in the thigh","shortLabel":"SVT \u2014 proximal long saphenous vein in thigh"},{"type":"cb","id":"usd_24_2","label":"Clinically suspected upper limb DVT","shortLabel":"Suspected upper limb DVT"},{"type":"cb","id":"usd_24_3","label":"Same day DVT US recommended by HNZ Haematology service or other secondary care specialist","shortLabel":"Same day US recommended by haematology/secondary care"}]},{"title":"Acute \u2014 within 48 hours","items":[{"type":"cb","id":"usd_48_1","label":"Clinically suspected lower limb DVT AND Well''s score of 2 or greater","shortLabel":"Suspected lower limb DVT \u2014 Well''s score 2+"},{"type":"cb","id":"usd_48_2","label":"Clinically suspected lower limb DVT AND Well''s score less than 2 AND positive D-dimer","shortLabel":"Suspected lower limb DVT \u2014 Well''s <2 with positive D-dimer"}]},{"title":"S1 \u2014 Specified date, within 1 week of target date","items":[{"type":"cb","id":"usd_s1_1","label":"No DVT seen on initial ultrasound but clinical suspicion remains high AND D-dimer positive AND high likelihood on Well''s score (2 or higher) \u2014 follow-up scan 5-8 days after initial scan","shortLabel":"High clinical suspicion, negative initial US \u2014 follow-up at 5-8 days"},{"type":"cb","id":"usd_s1_2","label":"Check for proximal clot extension in a calf DVT not being treated with anticoagulation, between 5-8 days after initial scan","shortLabel":"Calf DVT \u2014 check for proximal extension at 5-8 days"}]},{"title":"S2 \u2014 Specified date, within 2 weeks of target date","items":[{"type":"cb","id":"usd_s2_1","label":"Follow-up scan after anticoagulation therapy as recommended by secondary care specialist","shortLabel":"Follow-up post-anticoagulation therapy \u2014 secondary care recommended"}]}],"guidance":"Select the anatomical site being requested, then complete the clinical indicators. Note: maternity and gynaecological ultrasound is outside CRR scope \u2014 refer via separate pathway.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=32358.htm","guidanceNarrative":"Use Well''s score to stratify clinical suspicion. D-dimer should be used in conjunction with Well''s score.","alternativeManagement":"Children aged younger than 15 years \u2014 see local DVT HealthPathway. Pregnant women \u2014 see local DVT HealthPathway.","notFundedDetail":"Routine follow-up scanning to confirm clot resolution \u2014 this does not typically assist with decisions on duration of anticoagulation. Superficial venous thrombosis unless affecting the proximal long saphenous vein in the thigh.","outOfCriteriaNote":"Not routinely funded for: routine follow-up scanning to confirm clot resolution; superficial venous thrombosis unless affecting the proximal long saphenous vein in the thigh.","footnotes":"","safetyQuestions":[]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('us_msk', 'Ultrasound — Musculoskeletal (incl. Shoulder)', 'Ultrasound', 'multisite', 'adult', '{"examId":"us","examTitle":"Ultrasound","siteLabel":"Musculoskeletal (incl. Shoulder)","inlineGuidance":"No routine direct access to publicly funded (non-ACC) musculoskeletal ultrasound. Ultrasound findings alone do not typically change management. Initial management should always include a 2-3 month trial of physiotherapy. Radiology is not a prerequisite for a trial of steroid injection when red flags are excluded.","groups":[{"title":"P3-P4 \u2014 within 6 to 12 weeks","items":[{"type":"cb","id":"usmsk_1","label":"Secondary care clinician or Primary Care Radiology Liaison or radiologist advises referral for non-urgent shoulder or another musculoskeletal ultrasound","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent MSK)"}]}],"guidance":"Select the anatomical site being requested, then complete the clinical indicators. Note: maternity and gynaecological ultrasound is outside CRR scope \u2014 refer via separate pathway.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=15606.htm","guidanceNarrative":"70% of shoulder pain in general practice can be attributed to the rotator cuff complex. Rotator cuff tendonitis is the most common underlying pathology and most likely diagnosis in the absence of demonstrated weakness on examination. Most presentations with shoulder pain and suspected rotator cuff pathologies including smaller tears will resolve with conservative management and do not require imaging. Initial management should always include a 2-3 month trial of physiotherapy. Radiology is not a pre-requisite for a trial of steroid injection when a full clinical assessment has been undertaken and red flags excluded. There is no routine direct access to publicly funded (non-ACC) shoulder or other musculoskeletal ultrasound. Ultrasound findings alone do not typically change the management approach. If there is inadequate response to physiotherapy (+/- cortisone injection), management advice may be sought from secondary care and imaging requested on their recommendation or a case for imaging made to the PCRL.","alternativeManagement":"Shoulder pain with reduced passive range of motion and frozen shoulder is suspected \u2014 see local Shoulder Pain HealthPathway. Suspected olecranon or other bursitis \u2014 see local Shoulder Pain HealthPathway.","notFundedDetail":"Achilles or other tendon pain. Plantar fasciitis. Forefoot pain \u2014 suspected Morton''s neuroma. Tennis elbow. Golfer''s elbow. Tenosynovitis. Trochanteric pain (gluteal tendinopathy).","outOfCriteriaNote":"Not routinely funded for: Achilles or other tendon pain; plantar fasciitis; forefoot pain (suspected Morton''s neuroma); tennis elbow; golfer''s elbow; tenosynovitis; trochanteric pain (gluteal tendinopathy). If inadequate response to physiotherapy seek management advice from secondary care.","footnotes":"*1 Red flags: fever/systemically unwell; persistent night pain waking from sleep; pain at rest; restricted passive movement; inflammation/swelling.","safetyQuestions":[]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('us_neck_thyroid', 'Ultrasound — Neck / Thyroid', 'Ultrasound', 'multisite', 'adult', '{"examId":"us","examTitle":"Ultrasound","siteLabel":"Neck / Thyroid","inlineGuidance":"For palpable masses, FNA (preferably US-guided) provides better diagnostic accuracy than US alone and is the preferred initial diagnostic approach. Ultrasound reveals nodules in up to 65% of adults \u2014 the large majority are benign.","groups":[{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"usnt_p2_1","label":"Palpable thyroid nodule with suspicious features (painless rapid growth over 2-3 months, unexplained voice changes, youth/child, family history of MEN syndrome, enlarged neck lymph nodes) AND local pathway or secondary care specialist recommends referral for ultrasound","shortLabel":"Palpable thyroid nodule with suspicious features \u2014 specialist recommends US"},{"type":"cb","id":"usnt_p2_2","label":"FDG-avid incidental thyroid nodule on PET-CT scan of any size","shortLabel":"FDG-avid incidental thyroid nodule on PET-CT"},{"type":"cb","id":"usnt_p2_3","label":"Undifferentiated, solitary, non-pulsatile neck mass: present >3 weeks despite antibiotics AND larger than 1.5cm in diameter AND no obvious cause","shortLabel":"Solitary neck mass >1.5cm, present >3 wks despite antibiotics, no cause"},{"type":"cb","id":"usnt_p2_4","label":"Urgent Ultrasound Neck or Thyroid recommended by a secondary care clinician, PCRL, or radiologist","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)"}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"usnt_p3_1","label":"Palpable thyroid nodule, no suspicious features, euthyroid \u2014 initial imaging","shortLabel":"Palpable thyroid nodule, no suspicious features, euthyroid"},{"type":"cb","id":"usnt_p3_2","label":"Non-urgent Ultrasound Neck or Thyroid recommended by a secondary care clinician, PCRL, or radiologist","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)"}]},{"title":"P4 \u2014 Deferrable, within 6-12 weeks","items":[{"type":"cb","id":"usnt_p4_1","label":"Solitary impalpable incidental thyroid nodule (ITN) on CT or MR imaging, TSH normal or elevated AND nodule >10mm in patient aged <35 years OR >15mm in patient aged 35+ years OR any size with adverse features on CT/MR imaging","shortLabel":"Incidental thyroid nodule on CT/MR \u2014 meets size/age threshold"},{"type":"cb","id":"usnt_p4_2","label":"Multiple incidental thyroid nodules on CT or MR imaging, TSH normal or elevated, AND one or more nodules 20mm or more in longest diameter","shortLabel":"Multiple incidental thyroid nodules on CT/MR \u2014 one or more 20mm+"}]},{"title":"S2 \u2014 Specified date, within 2 weeks of target date","items":[{"type":"cb","id":"usnt_s2_1","label":"Non-urgent deferrable Ultrasound Neck or Thyroid recommended by a secondary care specialist, PCRL, or radiologist","shortLabel":"Deferrable US recommended by secondary care / PCRL / radiologist"},{"type":"cb","id":"usnt_s2_2","label":"Follow-up ultrasound recommended by a secondary care specialist or radiologist for a high-risk thyroid nodule previously identified on ultrasound, CT or MRI","shortLabel":"Follow-up for high-risk thyroid nodule \u2014 specialist recommended"}]}],"guidance":"Select the anatomical site being requested, then complete the clinical indicators. Note: maternity and gynaecological ultrasound is outside CRR scope \u2014 refer via separate pathway.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=20738.htm","guidanceNarrative":"Ultrasound is of limited value in the diagnostic work up of thyroid and neck masses. It can help confirm the origin of the mass and provide some characterisation but for palpable masses, fine needle aspiration (FNA \u2014 preferably ultrasound-guided) provides better diagnostic accuracy than ultrasound alone and is the preferred initial diagnostic approach where available. Ultrasound evaluation of the thyroid reveals nodules in up to 65% of adults depending on age and gender. The large majority are benign nodules. Thyroid cancer occurs in 7-15% of thyroid nodules. 85% of these are papillary cancers which don''t cause any ill-health or affect longevity and there is therefore no benefit in finding these cancers. Approximately 5% of thyroid nodules will harbour an important thyroid cancer (one likely to cause ill health in the future). The challenge is to identify the few clinically important cancers (medullary, anaplastic) but avoid using a lot of scarce resource working up all incidentally discovered nodules.","alternativeManagement":"Multiple neck masses or suspected metastatic lymphadenopathy \u2014 investigate and refer as per the Neck Lumps in Adults HealthPathway. Incidental thyroid nodule on CT scan or MRI and TSH reduced \u2014 refer for nuclear medicine Tc-99m pertechnetate scan. Goitre or diffuse thyroid swelling with severe obstructive symptoms (stridor, wheezing at rest) \u2014 refer for acute secondary care assessment as per local HealthPathway. Goitre or thyroid mass with mild to moderate obstructive symptoms \u2014 see local Goitre HealthPathway. Thyrotoxicosis/Hyperthyroidism \u2014 see local Hyperthyroidism HealthPathway. Hypothyroidism \u2014 see local Hypothyroid HealthPathway. If presenting symptoms do not meet criteria but ultrasound may be indicated \u2014 seek advice from PCRL or relevant secondary care specialist.","notFundedDetail":"ITN in patient with co-morbidities and limited life expectancy \u2014 imaging work up not recommended. Solitary ITN on CT or MR imaging smaller than 10mm in diameter and without adverse imaging or clinically suspicious features. Multiple nodules all smaller than 20mm in diameter and without any adverse features on CT or MR imaging and likely to be benign.","outOfCriteriaNote":"Not routinely funded for: ITN with co-morbidities and limited life expectancy; solitary ITN on CT/MR <10mm without adverse features; multiple nodules all <20mm without adverse features. Incidental thyroid nodule with reduced TSH \u2014 refer for nuclear medicine scan.","footnotes":"","safetyQuestions":[]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('us_pelvis', 'Ultrasound — Pelvis', 'Ultrasound', 'multisite', 'adult', '{"examId":"us","examTitle":"Ultrasound","siteLabel":"Pelvis","inlineGuidance":"In acute pelvic pain, ultrasound as a rule-out investigation is limited \u2014 acuity of presentation should determine referral to hospital vs community management. PID is commonly associated with a normal ultrasound and is typically a clinical diagnosis. Maori and Pacific peoples are disproportionately affected by endometrial cancer \u2014 lower threshold for investigation.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","items":[{"type":"cb","id":"usp_emerg_1","label":"Clinically unstable patients with suspected gynaecologic or pelvic cause","shortLabel":"Clinically unstable \u2014 suspected gynaecologic cause"}]},{"title":"Acute \u2014 within 24 hours","items":[{"type":"cb","id":"usp_24_1","label":"Sudden onset severe pelvic pain, clinically stable \u2014 suspected ovarian torsion or ovarian cyst accident (rupture or bleed)","shortLabel":"Sudden severe pelvic pain \u2014 suspected ovarian torsion or cyst accident"},{"type":"cb","id":"usp_24_2","label":"Possible endometritis from RPOC \u2014 persistent pelvic pain and tenderness +/- low grade fever +/- bleeding, outside 2-week post-miscarriage maternity-funded scan window","shortLabel":"Possible endometritis/RPOC \u2014 outside maternity scan window"},{"type":"cb","id":"usp_24_3","label":"IUCD strings missing or IUCD breaks on removal with only fragment removed AND symptoms suggestive of possible perforation (cramping pain, discharge, unexplained bleeding)","shortLabel":"IUCD missing/broken with symptoms of possible perforation"}]},{"title":"Acute \u2014 within 48 hours","items":[{"type":"cb","id":"usp_48_1","label":"Suspected ongoing pregnancy >14 days post abortion AND urine HCG >1000 IU at 14 days OR serial serum bHCG remains high/increased after EMA","shortLabel":"Suspected ongoing pregnancy >14 days post abortion \u2014 HCG criteria met"},{"type":"cb","id":"usp_48_2","label":"Secondary care clinician, PCRL or radiologist advises referral for same or next day ultrasound pelvis","shortLabel":"Advised by secondary care / PCRL / radiologist (same/next day)"}]},{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"usp_p2_1","label":"Pelvic mass on examination suspicious of cancer","shortLabel":"Pelvic mass suspicious of cancer on examination"},{"type":"cb","id":"usp_p2_2","label":"Post-menopausal bleeding (vaginal bleeding after >12 months amenorrhoea around expected age of menopause approximately 50 years)","shortLabel":"Post-menopausal bleeding"},{"type":"cb","id":"usp_p2_3","label":"Persistent post-menopausal bleeding at any age while on continuous combined MHT and it has been >6 months since starting therapy","shortLabel":"Persistent PMB on continuous combined MHT >6 months"},{"type":"cb","id":"usp_p2_4","label":"No palpable pelvic mass but new abdominal or pelvic symptoms on a persistent or frequent basis (>12 times/month) AND Ca-125 35 units/mL or greater irrespective of menopause status","shortLabel":"Persistent pelvic/abdominal symptoms >12x/month + Ca-125 35+"},{"type":"cb","id":"usp_p2_5","label":"AUB with non-uterine causes excluded AND woman of any age with AUB AND at least two risk factors for EH/EC OR pelvic mass suspected on examination with no prior imaging","shortLabel":"AUB with 2+ EH/EC risk factors, or suspected pelvic mass, no prior imaging"},{"type":"cb","id":"usp_p2_6","label":"Atypical (AG2) endometrial cells reported on cervical screening cytology in women of any age and menopause status","shortLabel":"AG2 endometrial cells on cervical cytology"},{"type":"cb","id":"usp_p2_7","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent US pelvis","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)"}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"usp_p3_1","label":"Women aged 45 years or older with AUB and non-uterine causes excluded","shortLabel":"AUB, non-uterine causes excluded, aged 45+"},{"type":"cb","id":"usp_p3_2","label":"Women aged younger than 45 years with AUB AND one or more risk factors for EH/EC","shortLabel":"AUB aged <45 with 1+ EH/EC risk factor"},{"type":"cb","id":"usp_p3_3","label":"Women aged younger than 45 years with AUB who have not responded to first-line treatment trialled for at least 3 months","shortLabel":"AUB aged <45 \u2014 failed first-line treatment 3+ months"},{"type":"cb","id":"usp_p3_4","label":"Perimenopausal woman on combined cyclical MHT with ongoing irregular bleeding or bleeding outside progestogen withdrawal, despite trial of increased progestogen, and it has been >6 months since starting MHT","shortLabel":"Perimenopausal \u2014 irregular bleeding on cyclical MHT >6 months"},{"type":"cb","id":"usp_p3_5","label":"Benign-appearing endometrial cells on cervical smear AND at least one of: post-menopausal; symptomatic; suspected mass on exam; 1+ EH/EC risk factor","shortLabel":"Benign endometrial cells on smear + post-menopausal or symptomatic or risk factor"},{"type":"cb","id":"usp_p3_6","label":"Suspected ovarian cyst (unilateral pelvic pain >4 weeks and/or unilateral tenderness) or other pelvic mass and low/uncertain suspicion of cancer","shortLabel":"Suspected ovarian cyst or pelvic mass \u2014 low cancer suspicion"},{"type":"cb","id":"usp_p3_7","label":"Pelvic pain >6 weeks, unrelated to menstrual cycle, with PID excluded as cause per local PID HealthPathway","shortLabel":"Chronic pelvic pain >6 weeks \u2014 PID excluded"},{"type":"cb","id":"usp_p3_8","label":"Primary amenorrhoea (absence of menarche by age 16 years, or age 14 years if absent secondary sexual characteristics)","shortLabel":"Primary amenorrhoea"},{"type":"cb","id":"usp_p3_9","label":"Secondary dysmenorrhoea \u2014 new onset, debilitating pain persists despite 3-month trial of medical management","shortLabel":"Secondary dysmenorrhoea \u2014 failed 3-month medical management"},{"type":"cb","id":"usp_p3_10","label":"Secondary care clinician, PCRL or radiologist advises referral for routine ultrasound pelvis","shortLabel":"Advised by secondary care / PCRL / radiologist (routine)"}]},{"title":"P4 \u2014 Deferrable, within 6-12 weeks","items":[{"type":"cb","id":"usp_p4_1","label":"PCOS suspected but only one of three Rotterdam diagnostic criteria fulfilled (hyperandrogenism, polycystic ovaries, irregular menses)","shortLabel":"Suspected PCOS \u2014 only 1 of 3 Rotterdam criteria met"},{"type":"cb","id":"usp_p4_2","label":"Known fibroid >5cm which becomes symptomatic (pelvic pressure, back pain, dyspareunia, urination difficulties) after commencing MHT","shortLabel":"Known fibroid >5cm \u2014 new symptoms after starting MHT"},{"type":"cb","id":"usp_p4_3","label":"Secondary care clinician, PCRL or radiologist advises referral for deferrable non-urgent ultrasound pelvis","shortLabel":"Advised by secondary care / PCRL / radiologist (deferrable)"}]}],"guidance":"Select the anatomical site being requested, then complete the clinical indicators. Note: maternity and gynaecological ultrasound is outside CRR scope \u2014 refer via separate pathway.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=15608.htm","guidanceNarrative":"In the acute pelvic pain presentation, the use of ultrasound as a ''rule out'' investigation is limited \u2014 the acuity of the presentation (and the expected management required) should remain the determining factor in referral to hospital vs community management. If the patient requires hospital assessment regardless of the ultrasound result, a community-provided acute demand ultrasound is typically not warranted unless specifically advised by a secondary care specialist. In suspected ovarian/adnexal torsion, ultrasound has good specificity (85-90%) but lower sensitivity (75-80%). Pelvic Inflammatory Disease (PID) remains the most common cause of acute pelvic pain. It is commonly associated with a normal ultrasound and is typically considered a clinical diagnosis. M\u0101ori and Pacific Peoples are disproportionately affected by endometrial cancer (EC) and endometrial hyperplasia (EH). Investigations including transvaginal ultrasound and/or aspiration endometrial sampling should be considered at or soon after initial presentation for all M\u0101ori and Pacific people presenting with abnormal uterine bleeding (AUB).","alternativeManagement":"Suspected retained products of conception (RPOC) with persistent or heavy bleeding after abortion or miscarriage \u2014 see local Abortion HealthPathway or Miscarriage HealthPathway. Suspected endometriosis in the absence of a clinically palpable mass \u2014 see local Endometriosis HealthPathway. Primary dysmenorrhoea in the absence of a clinically palpable mass \u2014 see local Dysmenorrhoea HealthPathway. Pelvic inflammatory disease in the absence of a clinically palpable mass \u2014 see local PID HealthPathway. Cervical polyps \u2014 referral to secondary care rather than ultrasound is recommended for women with polyps which prove difficult to remove. Secondary amenorrhoea \u2014 pelvic USS is not normally helpful unless a pelvic mass is present or the patient has significantly raised androgens.","notFundedDetail":"Routine follow-up of known fibroids. Subfertility. Follow-up of asymptomatic simple ovarian cyst (O-RADS 2) less than 3cm in diameter in post-menopausal woman. Follow-up of asymptomatic simple ovarian cyst (O-RADS 2) less than 5cm in diameter in premenopausal woman. Follow-up of asymptomatic non-simple ovarian cyst less than 3cm diameter in premenopausal woman. Follow-up of typical-appearing haemorrhagic cyst up to 5cm diameter in pre-menopausal woman. Benign-appearing endometrial cells on smear in asymptomatic pre-menopausal women with no abnormality on exam and without any risk factors for EH/EC. Erratic unscheduled bleeding in the first 3 to 6 months after starting MHT. Screening ultrasound for family history of ovarian cancer (refer to secondary care instead). Women aged less than 45 years with AUB and no risk factors for EH/EC, no abnormality on examination, and where first-line treatment has not been trialled.","outOfCriteriaNote":"Not routinely funded for: routine follow-up of known fibroids; subfertility; follow-up of asymptomatic simple ovarian cyst (O-RADS 2) <3cm post-menopausal or <5cm pre-menopausal; screening for ovarian cancer family history (refer to secondary care). Women aged <45 with AUB, no risk factors, no abnormality on exam, and first-line treatment not yet trialled.","footnotes":"*1 Patients with suspected endometritis: suspected infection with ongoing pelvic pain post-partum/miscarriage/abortion, uterine tenderness, with or without fever and/or bleeding but systemically stable. If systemically unstable and/or severe persistent pelvic pain refer for acute assessment without requesting imaging.\n*2 Presentations warranting consideration of ovarian cancer in absence of palpable mass \u2014 new abdominal or pelvic symptoms on persistent or frequent basis (particularly more than 12 times per month): persistent abdominal distension or bloating; early satiety or loss of appetite; pelvic or abdominal pain without a known cause; increased urinary urgency or frequency; irritable bowel symptoms especially if new onset and aged over 50; unexplained weight loss or fatigue.\n*3 Abnormal Uterine Bleeding (AUB): bleeding from the uterus that is abnormal in volume, regularity, frequency or duration in the absence of pregnancy (excluding postmenopausal bleeding). May be acute (urgent referral) or chronic (6 months or more). Includes heavy menstrual bleeding, irregular cycles (10+ days variation), prolonged menstrual bleeding (>8 days), secondary amenorrhoea, infrequent cycles (<every 38 days), frequent cycles (>every 24 days), intermenstrual bleeding, post-coital bleeding, and unscheduled bleeding on hormonal medication.\n*4 Non-uterine causes of bleeding: vulvovaginal atrophy/atrophic vaginitis; vulval dermatoses; STIs including chlamydia; malignancy of cervix/vagina/vulva; cervical ectropion; urethral causes.\n*5 Risk factors for EH/EC: BMI greater than 30; diabetes mellitus (Types I and II); Pacific and M\u0101ori ethnicity; PCOS and/or chronic anovulation; unopposed oestrogen therapy; nulliparity and older than 35; early menarche (less than 10 years old); family history of endometrial, ovarian, breast or bowel cancer; oestrogen-secreting tumour.","safetyQuestions":[]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('us_renal', 'Ultrasound — Renal', 'Ultrasound', 'multisite', 'adult', '{"examId":"us","examTitle":"Ultrasound","siteLabel":"Renal","inlineGuidance":"Suspected renal colic in a non-pregnant person: see CT KUB pathway. Macroscopic haematuria aged 40-85: prefer CT IVU.","groups":[{"title":"Acute \u2014 within 24 hours","items":[{"type":"cb","id":"usr_24_1","label":"Renal colic if pregnant or female younger than 35 with uncomplicated presentation (CT KUB/radiation not warranted) AND no history of stones, no solitary kidney, no haematuria/fever","shortLabel":"Renal colic \u2014 pregnant or female <35, no CT KUB indication"},{"type":"cb","id":"usr_24_2","label":"Pyelonephritis with fever >38 degrees, pyuria on microscopy, loin pain/tenderness AND not responding to antibiotics after 72 hours OR flank pain not improving within 24hr IV / 48hr oral antibiotics","shortLabel":"Pyelonephritis \u2014 not responding to antibiotics"}]},{"title":"Acute \u2014 within 48 hours","items":[{"type":"cb","id":"usr_48_1","label":"Acute renal function deterioration \u2014 serum creatinine increase >50 micromol/L in 7 days or >25 micromol/L in 2 days (discussion with secondary care/PCRL recommended)","shortLabel":"Acute renal function deterioration \u2014 creatinine threshold met"},{"type":"cb","id":"usr_48_2","label":"Suspected chronic urinary retention (new onset incontinence with palpable enlarged bladder)","shortLabel":"Suspected chronic urinary retention \u2014 palpable enlarged bladder"},{"type":"cb","id":"usr_48_3","label":"Secondary care clinician, PCRL or radiologist advises referral for acute ultrasound renal","shortLabel":"Advised by secondary care / PCRL / radiologist (acute)"}]},{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"usr_p2_1","label":"Macroscopic haematuria \u2014 if younger than 40 years or aged 86 years and older","shortLabel":"Macroscopic haematuria \u2014 aged <40 or 86+"},{"type":"cb","id":"usr_p2_2","label":"Macroscopic haematuria \u2014 aged 40 to 85 and unable to have intravenous contrast (eGFR <45 or iodine contrast allergy)","shortLabel":"Macroscopic haematuria \u2014 aged 40-85, contrast contraindicated"},{"type":"cb","id":"usr_p2_3","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent ultrasound renal","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)"}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"usr_p3_1","label":"Microscopic haematuria \u2014 male patient, older than 50 years, current or ex-smoker","shortLabel":"Microscopic haematuria \u2014 male >50, current or ex-smoker"},{"type":"cb","id":"usr_p3_2","label":"New diagnosis of CKD and any of: eGFR <30; eGFR <45 with diabetes; eGFR <60 with evidence of progressive disease (eGFR decreased 15+ in previous 12 months); ACR >250","shortLabel":"New CKD \u2014 eGFR or ACR threshold met"},{"type":"cb","id":"usr_p3_3","label":"New right-sided or bilateral varicocele","shortLabel":"New right-sided or bilateral varicocele"},{"type":"cb","id":"usr_p3_4","label":"UTI in men \u2014 recurrent (2 or more confirmed UTI) OR persistent (persistent bacteriuria with same organism after treatment \u2014 consider renal tract stone; refer for KUB X-ray along with renal US)","shortLabel":"UTI in men \u2014 recurrent or persistent (refer for KUB X-ray also)"},{"type":"cb","id":"usr_p3_5","label":"UTI in women \u2014 recurrent (>3 UTIs in a year or >2 in 6 months despite prophylactic antibiotics) OR persistent bacteriuria with same organism after treatment","shortLabel":"UTI in women \u2014 recurrent or persistent"},{"type":"cb","id":"usr_p3_6","label":"Urinary incontinence in men with palpable bladder, or new or deteriorating renal impairment","shortLabel":"Urinary incontinence in men \u2014 palpable bladder or deteriorating renal function"},{"type":"cb","id":"usr_p3_7","label":"Recurrent loin pain suggesting renal tract obstruction other than renal stone","shortLabel":"Recurrent loin pain \u2014 suspected renal tract obstruction (not stone)"},{"type":"cb","id":"usr_p3_8","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent ultrasound renal","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)"}]},{"title":"P4 \u2014 Deferrable, within 6-12 weeks","items":[{"type":"cb","id":"usr_p4_1","label":"Microscopic haematuria \u2014 male patient, aged younger than 50 years","shortLabel":"Microscopic haematuria \u2014 male <50"},{"type":"cb","id":"usr_p4_2","label":"Microscopic haematuria \u2014 female, of any age","shortLabel":"Microscopic haematuria \u2014 female, any age"}]}],"guidance":"Select the anatomical site being requested, then complete the clinical indicators. Note: maternity and gynaecological ultrasound is outside CRR scope \u2014 refer via separate pathway.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=19858.htm","guidanceNarrative":"Suspected renal colic in a non-pregnant person \u2014 see local Renal Colic and Urinary Tract Stones HealthPathway. Macroscopic haematuria in patients who do not have a UTI, if aged 40 to 85 years \u2014 refer for CT IVU (Intravenous Urogram) as the preferred investigation.","alternativeManagement":"Incidental finding on ultrasound of a solid lesion more than 1cm diameter with typical ultrasound appearances of an angiomyolipoma \u2014 see local CT IVU HealthPathway. Macroscopic haematuria aged 40 to 85 years without UTI \u2014 refer for CT IVU. Repeat renal ultrasound for diabetic patients with known diabetic renal complications is not indicated. Acute kidney injury \u2014 manage according to Acute Kidney Injury pathway or seek advice from relevant secondary care specialist. Enlarged prostate or elevated PSA \u2014 see local Prostate Cancer Diagnosis HealthPathway. Isolated proteinuria \u2014 seek nephrology advice. Lower urinary tract symptoms \u2014 see local LUTS or Benign Prostatic Hypertrophy HealthPathway.","notFundedDetail":"Recurrent UTIs in women except as documented in criteria. Investigation of uncomplicated hypertension. Bacteriuria in patients with in-dwelling catheters who are not systemically unwell. Follow-up imaging of simple renal cysts (Bosniak I and II). Follow-up of incidental finding on ultrasound of a solid lesion less than 1cm diameter with typical appearances of an angiomyolipoma. Screening scan for Autosomal Dominant Polycystic Kidney Disease (ADPKD). Serial ultrasounds of known polycystic kidneys unless indicated by the radiology report or the patient develops new symptoms meeting criteria.","outOfCriteriaNote":"Not routinely funded for: recurrent UTIs in women (except as above); investigation of uncomplicated hypertension; bacteriuria in catheterised patients who are not systemically unwell; follow-up of simple renal cysts (Bosniak I and II); screening for ADPKD.","footnotes":"","safetyQuestions":[]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('us_scrotum', 'Ultrasound — Scrotum', 'Ultrasound', 'multisite', 'adult', '{"examId":"us","examTitle":"Ultrasound","siteLabel":"Scrotum","inlineGuidance":"New right-sided or bilateral varicocele: arrange renal US to exclude renal cancer with IVC involvement.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","items":[{"type":"cb","id":"ussc_emerg_1","label":"Suspected testicular torsion","shortLabel":"Suspected testicular torsion"},{"type":"cb","id":"ussc_emerg_2","label":"Strangulated inguinal hernia","shortLabel":"Strangulated inguinal hernia"}]},{"title":"Acute \u2014 within 48 hours","items":[{"type":"cb","id":"ussc_48_1","label":"High suspicion of testicular cancer (rapidly growing mass, non-transilluminating, not able to distinguish mass from testis, painless)","shortLabel":"High suspicion of testicular cancer"},{"type":"cb","id":"ussc_48_2","label":"Secondary care clinician, PCRL or radiologist advises referral for acute ultrasound","shortLabel":"Advised by secondary care / PCRL / radiologist (acute)"}]},{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"ussc_p2_1","label":"New hydrocoele in adults (may be secondary to testicular cancer)","shortLabel":"New hydrocoele in adult"},{"type":"cb","id":"ussc_p2_2","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent ultrasound","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)"}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"ussc_p3_1","label":"Scrotal lumps where it is unclear whether the swelling is testicular or extra-testicular, and is non-transilluminating","shortLabel":"Scrotal lump \u2014 unclear testicular/extra-testicular, non-transilluminating"},{"type":"cb","id":"ussc_p3_2","label":"Epididymo-orchitis which fails to respond to antibiotic treatment after 7-10 days","shortLabel":"Epididymo-orchitis not responding to antibiotics at 7-10 days"},{"type":"cb","id":"ussc_p3_3","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent ultrasound","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)"}]},{"title":"P4 \u2014 Deferrable, within 6-12 weeks","items":[{"type":"cb","id":"ussc_p4_1","label":"Benign scrotal lumps larger than 5cm causing significant impairment in quality of life (affecting employment and/or activities of daily living) and patient is seeking surgery","shortLabel":"Benign scrotal lump >5cm \u2014 significant QOL impact, seeking surgery"}]}],"guidance":"Select the anatomical site being requested, then complete the clinical indicators. Note: maternity and gynaecological ultrasound is outside CRR scope \u2014 refer via separate pathway.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=29070.htm","guidanceNarrative":"New right-sided or bilateral varicocele \u2014 arrange renal ultrasound to exclude renal cancer with inferior vena cava (IVC) involvement.","alternativeManagement":"New right-sided or bilateral varicocele \u2014 arrange renal US to exclude renal cancer with IVC involvement.","notFundedDetail":"Non-solid (transilluminating) scrotal masses smaller than 5cm. Long-standing hydrocele in adults. Routine follow-up of testicular microlithiasis. Haematospermia \u2014 almost always benign and self-limiting. Uncomplicated epididymo-orchitis. Orchalgia (chronic testicular or scrotal pain in the absence of any abnormality on examination). Scrotal pearls or stones (calcified extra-testicular loose bodies).","outOfCriteriaNote":"Not routinely funded for: non-solid (transilluminating) scrotal masses <5cm; long-standing hydrocele in adults; routine follow-up of testicular microlithiasis; haematospermia; uncomplicated epididymo-orchitis; orchalgia in absence of abnormality on examination; scrotal pearls.","footnotes":"","safetyQuestions":[]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('us_soft_tissue', 'Ultrasound — Soft Tissue', 'Ultrasound', 'multisite', 'adult', '{"examId":"us","examTitle":"Ultrasound","siteLabel":"Soft Tissue","inlineGuidance":"Soft tissue sarcomas are frequently slow growing and painless \u2014 do not be reassured by absence of pain.","groups":[{"title":"Acute \u2014 within 48 hours","items":[{"type":"cb","id":"usst_48_1","label":"Localisation of a suspected foreign body for removal (only if not eligible for ACC funding)","shortLabel":"Suspected foreign body \u2014 not ACC eligible"}]},{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"usst_p2_1","label":"New lump on trunk or limbs with any of: deep to deep fascia, fixed, hard, irregular of any size; larger than 5cm; changing rapidly; painful; recurring after a previous sarcoma excision","shortLabel":"New trunk/limb lump with suspicious features (deep/hard/large/rapid/recurrent)"},{"type":"cb","id":"usst_p2_2","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent ultrasound","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)"}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"usst_p3_1","label":"New lump on trunk or limbs \u2014 superficial, mobile, and larger than 5cm in diameter with uncertain diagnosis OR smaller than 5cm with uncertain whether deep to fascia (fixed)","shortLabel":"New trunk/limb lump \u2014 superficial >5cm uncertain, or <5cm uncertain re fascia"},{"type":"cb","id":"usst_p3_2","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent ultrasound","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)"}]}],"guidance":"Select the anatomical site being requested, then complete the clinical indicators. Note: maternity and gynaecological ultrasound is outside CRR scope \u2014 refer via separate pathway.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=479698.htm","guidanceNarrative":"Soft tissue sarcomas are frequently slow growing and painless \u2014 do not be reassured by the absence of pain.","alternativeManagement":"Localisation of a suspected foreign body for removal and eligible for ACC funding \u2014 use ACC funding. Isolated neck lumps or enlarged lymph node \u2014 see local US Thyroid/Neck HealthPathway. Isolated enlarged axillary lump presumed to be a lymph node \u2014 see local Breast Symptoms HealthPathway. Suspected breast abscess \u2014 see local Mastitis and Breast Abscess HealthPathway. Breast lumps \u2014 see local Breast Symptoms HealthPathway.","notFundedDetail":"Soft tissue mass with characteristic appearance of lipomas, ganglions, cysts and no concerning features. Suspected abscess \u2014 see local Soft Tissue Abscesses HealthPathway.","outOfCriteriaNote":"Not routinely funded for: soft tissue mass with characteristic appearance of lipomas, ganglions, cysts and no concerning features; suspected abscess. Isolated neck lumps \u2014 see US Thyroid/Neck pathway.","footnotes":"","safetyQuestions":[]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('xr_chest', 'X-Ray — Chest', 'X-Ray', 'multisite', 'adult', '{"examId":"xr","examTitle":"X-Ray","siteLabel":"Chest","inlineGuidance":"CXR is the initial investigation for suspected lung cancer \u2014 CT Chest is a subsequent step. In patients with acute lower respiratory tract infection, a CXR does not change management in most cases.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","items":[{"type":"cb","id":"xrc_emerg_1","label":"Haemoptysis with red flags: significant (>20ml single episode or >100ml/hour) or life-threatening; haemodynamically unstable; haemoptysis with hoarseness or stridor; acute dyspnoea and/or chest pain with haemoptysis","shortLabel":"Life-threatening or red flag haemoptysis"},{"type":"cb","id":"xrc_emerg_2","label":"Severe respiratory distress","shortLabel":"Severe respiratory distress"},{"type":"cb","id":"xrc_emerg_3","label":"Suspected large pneumothorax with significant pain, breathlessness, tachycardia","shortLabel":"Suspected large pneumothorax"},{"type":"cb","id":"xrc_emerg_4","label":"Suspected active Tuberculosis and patient is acutely unwell \u2014 follow the Tuberculosis pathway","shortLabel":"Suspected active TB \u2014 acutely unwell"}]},{"title":"Acute \u2014 within 24 hours","items":[{"type":"cb","id":"xrc_24_1","label":"Suspected community-acquired pneumonia (CAP) with unexpectedly severe or atypical presentation, or patient considered at risk of underlying lung pathology (e.g. lung cancer)","shortLabel":"Suspected CAP \u2014 severe/atypical or at risk of underlying lung pathology"},{"type":"cb","id":"xrc_24_2","label":"Respiratory tract infection with possible left ventricular failure","shortLabel":"LRTI with possible left ventricular failure"}]},{"title":"Acute \u2014 within 48 hours","items":[{"type":"cb","id":"xrc_48_1","label":"Unexplained, new, or worsening dyspnoea","shortLabel":"Unexplained new/worsening dyspnoea"},{"type":"cb","id":"xrc_48_2","label":"Unexplained cough, persisting and worsening for more than 3 weeks","shortLabel":"Unexplained cough >3 weeks"},{"type":"cb","id":"xrc_48_3","label":"Unexplained chest and/or shoulder pain persisting for more than 3 weeks","shortLabel":"Unexplained chest/shoulder pain >3 weeks"},{"type":"cb","id":"xrc_48_4","label":"Unexplained changes in existing symptoms in patients with underlying chronic respiratory problems persisting for more than 3 weeks","shortLabel":"Unexplained change in chronic respiratory symptoms >3 weeks"},{"type":"cb","id":"xrc_48_5","label":"Persistent unexplained hoarseness persisting for more than 3 weeks","shortLabel":"Unexplained hoarseness >3 weeks"},{"type":"cb","id":"xrc_48_6","label":"Recurrent or unresolved chest infections","shortLabel":"Recurrent or unresolved chest infections"},{"type":"cb","id":"xrc_48_7","label":"Persistent unexplained haemoptysis in the absence of red flags","shortLabel":"Persistent unexplained haemoptysis (no red flags)"},{"type":"cb","id":"xrc_48_8","label":"Unexplained weight loss and loss of appetite persisting for more than 3 weeks","shortLabel":"Unexplained weight loss and loss of appetite >3 weeks"},{"type":"cb","id":"xrc_48_9","label":"Unexplained abnormal chest signs persisting more than 3 weeks not yet investigated (e.g. suspected pleural effusion)","shortLabel":"Unexplained abnormal chest signs >3 weeks \u2014 not yet imaged"},{"type":"cb","id":"xrc_48_10","label":"New supraclavicular lymphadenopathy","shortLabel":"New supraclavicular lymphadenopathy"},{"type":"cb","id":"xrc_48_11","label":"New cervical lymphadenopathy persisting >3 weeks, nodes >1cm in patient with other lung cancer symptoms/signs/risk factors","shortLabel":"Cervical lymphadenopathy >3 wks, >1cm, with lung cancer risk factors"},{"type":"cb","id":"xrc_48_12","label":"Features suggestive of paraneoplastic syndromes (e.g. hypercalcaemia, hypertrophic osteoarthropathy with painful swollen joints and finger/toe clubbing)","shortLabel":"Features of paraneoplastic syndrome"},{"type":"cb","id":"xrc_48_13","label":"Subacute dyspnoea of unknown cause (e.g. suspected pleural effusion or left ventricular failure)","shortLabel":"Subacute dyspnoea \u2014 suspected pleural effusion or LVF"},{"type":"cb","id":"xrc_48_14","label":"Lower respiratory tract infection not responded as expected after 48 hours of antibiotic treatment","shortLabel":"LRTI not responding to antibiotics at 48 hours"},{"type":"cb","id":"xrc_48_15","label":"Suspected small pneumothorax","shortLabel":"Suspected small pneumothorax"},{"type":"cb","id":"xrc_48_16","label":"Secondary care clinician, PCRL or radiologist advises referral for acute CXR","shortLabel":"Advised by secondary care / PCRL / radiologist (acute)"}]},{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"xrc_p2_1","label":"Suspected tuberculosis \u2014 follow the Tuberculosis pathway and request CXR if indicated","shortLabel":"Suspected tuberculosis \u2014 per Tuberculosis pathway"},{"type":"cb","id":"xrc_p2_2","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent CXR","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)"}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"xrc_p3_1","label":"Chronic cough (more than 8 weeks)","shortLabel":"Chronic cough >8 weeks"},{"type":"cb","id":"xrc_p3_2","label":"Chronic dyspnoea","shortLabel":"Chronic dyspnoea"},{"type":"cb","id":"xrc_p3_3","label":"Known cardiorespiratory disease unresponsive to treatment (e.g. COPD, ILD, bronchiectasis, sarcoidosis)","shortLabel":"Known cardiorespiratory disease unresponsive to treatment"},{"type":"cb","id":"xrc_p3_4","label":"History of asbestos exposure and no previous chest x-ray","shortLabel":"Asbestos exposure history \u2014 no prior CXR"},{"type":"cb","id":"xrc_p3_5","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent CXR","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)"}]},{"title":"S2 \u2014 Specified date, within 2 weeks of target date","items":[{"type":"cb","id":"xrc_s2_1","label":"6-week follow-up CXR after chest infection AND patient has ongoing symptoms/signs OR suspicious radiological features noted OR recommended by secondary care/radiologist","shortLabel":"6-week follow-up CXR post chest infection \u2014 criteria met"},{"type":"cb","id":"xrc_s2_2","label":"Post-cancer surveillance with documented specialist recommendation","shortLabel":"Post-cancer surveillance \u2014 specialist recommended"},{"type":"cb","id":"xrc_s2_3","label":"Follow-up of nodules detected on CXR or CT if recommended by secondary care clinician or radiologist","shortLabel":"Nodule follow-up \u2014 secondary care/radiologist recommended"},{"type":"cb","id":"xrc_s2_4","label":"Secondary care clinician, PCRL or radiologist advises referral for follow-up CXR","shortLabel":"Advised by secondary care / PCRL / radiologist (follow-up)"}]}],"guidance":"Select the anatomical site being requested, then complete the clinical indicators. Osteoarthritis is typically a clinical diagnosis \u2014 X-ray is not routinely needed. X-rays to assist diagnosis are reserved for persisting joint pain with features atypical for osteoarthritis.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=20715.htm","guidanceNarrative":"In patients with an acute lower respiratory tract infection, a chest x-ray does not change management in most cases.","alternativeManagement":"Ongoing unexplained respiratory symptoms after a negative CXR result, especially if clinical concern of malignancy \u2014 seek secondary care specialist assessment, or see the local Lung Cancer HealthPathway, or see the local CT Chest, Abdomen and Pelvis HealthPathway.","notFundedDetail":"Routine follow-up of pneumonia findings on chest x-ray other than in the S2 priority scenarios. Asbestos exposure surveillance. Heart murmur unless signs of complications such as heart failure. Lung cancer screening. Follow-up of nodules detected on CXR or CT except with documented recommendation of a hospital secondary care clinician or radiologist. TB screening in absence of positive skin or blood test. Rib views. Chest x-rays for immigration purposes. Routine lateral x-ray view when requesting a PA image. Routine investigation of hypertension. Amiodarone, methotrexate, or nitrofurantoin monitoring in asymptomatic patients.","outOfCriteriaNote":"Not routinely funded for: routine follow-up of pneumonia (except S2 above); asbestos exposure surveillance; heart murmur without complications; lung cancer screening; rib views; immigration purposes; routine lateral view with PA; routine investigation of hypertension; asymptomatic drug monitoring.","footnotes":"","safetyQuestions":[]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('xr_abdomen', 'X-Ray — Abdomen', 'X-Ray', 'multisite', 'adult', '{"examId":"xr","examTitle":"X-Ray","siteLabel":"Abdomen","inlineGuidance":"AXR does not reliably diagnose constipation and should not be used to monitor response to treatment. Sensitivity and specificity of AXR for bowel obstruction is low \u2014 CT is preferable.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","items":[{"type":"cb","id":"xra_emerg_1","label":"Acute abdomen including suspected obstruction","shortLabel":"Acute abdomen / suspected obstruction"}]},{"title":"Acute \u2014 within 48 hours","items":[{"type":"cb","id":"xra_48_1","label":"Diagnosis of constipation where patient history is unobtainable","shortLabel":"Constipation \u2014 patient history unobtainable"},{"type":"cb","id":"xra_48_2","label":"Secondary care clinician, PCRL or radiologist advises referral for acute x-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (acute)"}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"xra_p3_1","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent x-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)"}]},{"title":"S2 \u2014 Specified date, within 2 weeks of target date","items":[{"type":"cb","id":"xra_s2_1","label":"Follow-up of radio-opaque renal tract stones with a KUB x-ray (evident on CT scout view)","shortLabel":"KUB X-ray follow-up for radio-opaque renal tract stone"}]}],"guidance":"Select the anatomical site being requested, then complete the clinical indicators. Osteoarthritis is typically a clinical diagnosis \u2014 X-ray is not routinely needed. X-rays to assist diagnosis are reserved for persisting joint pain with features atypical for osteoarthritis.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=20715.htm","guidanceNarrative":"There is wide variation in the amount of normal faecal residue shown on AXR \u2014 it does not reliably diagnose constipation nor should it be used for monitoring response to treatment. The sensitivity and specificity of AXR is low in both the diagnosis and identifying underlying cause of bowel obstruction. As a more definitive test, CT is preferable and AXR may result in delays to a more definitive test.","alternativeManagement":"Suspected colorectal cancer \u2014 see local Colorectal Symptoms HealthPathway.","notFundedDetail":"Vague central abdominal pain. Suspected constipation other than in a patient group specified in the criteria.","outOfCriteriaNote":"Not routinely funded for: vague central abdominal pain; suspected constipation other than in a patient group specified above.","footnotes":"","safetyQuestions":[]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('xr_ankle_foot', 'X-Ray — Ankle / Foot', 'X-Ray', 'multisite', 'adult', '{"examId":"xr","examTitle":"X-Ray","siteLabel":"Ankle / Foot","inlineGuidance":"Osteoarthritis is typically a clinical diagnosis. X-rays reserved for persisting joint pain with features atypical for OA (patient <45; recent trauma; signs of inflammation; nocturnal pain; weight loss; inability to weight bear).","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","items":[{"type":"cb","id":"xraf_emerg_1","label":"Suspected septic arthritis","shortLabel":"Suspected septic arthritis"}]},{"title":"Acute \u2014 within 48 hours","items":[{"type":"cb","id":"xraf_48_1","label":"Secondary care clinician, PCRL or radiologist advises referral for acute x-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (acute)"}]},{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"xraf_p2_1","label":"Pain with red flags: persistent deep pain unrelated to activity OR unexplained night pain","shortLabel":"Red flag pain \u2014 deep/persistent or unexplained night pain"},{"type":"cb","id":"xraf_p2_2","label":"New, unexplained bony swelling or joint deformity","shortLabel":"New unexplained bony swelling or joint deformity"}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"xraf_p3_1","label":"Undiagnosed pain >4 weeks with clinical features not typical of osteoarthritis suggesting alternate pathology (patient <45; recent trauma; signs of inflammation; nocturnal pain; weight loss; systemic symptoms; inability to weight bear)","shortLabel":"Undiagnosed pain >4 weeks \u2014 features atypical for OA"},{"type":"cb","id":"xraf_p3_2","label":"Osteoarthritis with significant functional impairment, requesting orthopaedic assessment (x-ray of affected joint only)","shortLabel":"OA with significant functional impairment \u2014 requesting orthopaedic assessment"},{"type":"cb","id":"xraf_p3_3","label":"Pain in previous arthroplasty","shortLabel":"Pain in previous arthroplasty"},{"type":"cb","id":"xraf_p3_4","label":"Multiple joint swelling >6 weeks and inflammatory arthritis is suspected","shortLabel":"Multiple joint swelling >6 weeks \u2014 suspected inflammatory arthritis"},{"type":"cb","id":"xraf_p3_5","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent x-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)"}]}],"guidance":"Select the anatomical site being requested, then complete the clinical indicators. Osteoarthritis is typically a clinical diagnosis \u2014 X-ray is not routinely needed. X-rays to assist diagnosis are reserved for persisting joint pain with features atypical for osteoarthritis.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=20715.htm","guidanceNarrative":"Osteoarthritis is typically a clinical diagnosis and X-ray is not routinely needed to make the diagnosis. Imaging is also not required for effective non-surgical management of osteoarthritis. There is generally poor correlation between symptoms and X-ray changes \u2014 X-rays are poor indicators of the severity of disease except in advanced stages. X-rays to help with diagnosis are reserved for patients who present with persisting joint pain and clinical features atypical for osteoarthritis (e.g. younger age less than 45 years, pain at rest rather than with activity, persisting stiffness, systemic features).","alternativeManagement":"Acute gout \u2014 see local Gout HealthPathway.","notFundedDetail":"Clinically suspected osteoarthritis except as above. Bunions and bunionettes. Flat feet. Heel pain. Heel spurs. Plantar fasciitis. Suspected Sever''s Disease.","outOfCriteriaNote":"Not routinely funded for: clinically suspected OA (except above); bunions; flat feet; heel pain/spurs; plantar fasciitis; Sever''s disease; acute gout.","footnotes":"*1 Clinical features atypical for osteoarthritis and suggesting an alternative pathology: patient younger than 45; recent trauma; prominent signs of inflammation (tender swelling, redness, warmth, early morning stiffness for more than 30 minutes); significant nocturnal pain or pain at rest; weight loss or systemic symptoms; inability to weight bear.","safetyQuestions":[]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('xr_elbow', 'X-Ray — Elbow', 'X-Ray', 'multisite', 'adult', '{"examId":"xr","examTitle":"X-Ray","siteLabel":"Elbow","inlineGuidance":"Osteoarthritis is typically a clinical diagnosis. X-rays reserved for persisting joint pain with features atypical for OA.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","items":[{"type":"cb","id":"xre_emerg_1","label":"Suspected septic arthritis","shortLabel":"Suspected septic arthritis"}]},{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"xre_p2_1","label":"Pain with red flags: persistent deep pain unrelated to activity OR unexplained night pain","shortLabel":"Red flag pain \u2014 deep/persistent or unexplained night pain"},{"type":"cb","id":"xre_p2_2","label":"New, unexplained bony swelling or joint deformity","shortLabel":"New unexplained bony swelling or joint deformity"},{"type":"cb","id":"xre_p2_3","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent x-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)"}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"xre_p3_1","label":"Undiagnosed joint pain >4 weeks with clinical features not typical of osteoarthritis suggesting alternate pathology","shortLabel":"Undiagnosed joint pain >4 weeks \u2014 features atypical for OA"},{"type":"cb","id":"xre_p3_2","label":"Known osteoarthritis with significant functional impairment, requesting orthopaedic assessment for surgery and no x-ray in last 6 months (affected joint only)","shortLabel":"OA with significant functional impairment \u2014 requesting orthopaedic assessment"},{"type":"cb","id":"xre_p3_3","label":"Pain in previous arthroplasty","shortLabel":"Pain in previous arthroplasty"},{"type":"cb","id":"xre_p3_4","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent x-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)"}]}],"guidance":"Select the anatomical site being requested, then complete the clinical indicators. Osteoarthritis is typically a clinical diagnosis \u2014 X-ray is not routinely needed. X-rays to assist diagnosis are reserved for persisting joint pain with features atypical for osteoarthritis.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=20715.htm","guidanceNarrative":"Osteoarthritis is typically a clinical diagnosis and X-ray is not routinely needed to make the diagnosis. Imaging is not required for effective non-surgical management of osteoarthritis. There is generally poor correlation between symptoms and X-ray changes. X-rays to help with diagnosis are reserved for patients with persisting joint pain and clinical features atypical for osteoarthritis.","alternativeManagement":"Acute gout \u2014 see local Gout HealthPathway.","notFundedDetail":"Clinically suspected osteoarthritis except as above. Epicondylitis (tennis elbow, golfer''s elbow).","outOfCriteriaNote":"Not routinely funded for: clinically suspected OA (except above); epicondylitis (tennis elbow, golfer''s elbow).","footnotes":"*1 Clinical features atypical for osteoarthritis: patient younger than 45; recent trauma; prominent signs of inflammation (tender swelling, redness, warmth, early morning stiffness for more than 30 minutes); significant nocturnal pain or pain at rest; weight loss or systemic symptoms; inability to weight bear.","safetyQuestions":[]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('xr_knee', 'X-Ray — Knee', 'X-Ray', 'multisite', 'adult', '{"examId":"xr","examTitle":"X-Ray","siteLabel":"Knee","inlineGuidance":"Always request weight-bearing views of knees, especially if considering referral for orthopaedic assessment.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","items":[{"type":"cb","id":"xrk_emerg_1","label":"Suspected septic arthritis","shortLabel":"Suspected septic arthritis"}]},{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"xrk_p2_1","label":"Pain with red flags: persistent deep pain unrelated to activity OR unexplained night pain","shortLabel":"Red flag pain \u2014 deep/persistent or unexplained night pain"},{"type":"cb","id":"xrk_p2_2","label":"New, unexplained bony swelling or joint deformity","shortLabel":"New unexplained bony swelling or joint deformity"},{"type":"cb","id":"xrk_p2_3","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent x-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)"}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"xrk_p3_1","label":"Undiagnosed joint pain >4 weeks clinically inconsistent with osteoarthritis","shortLabel":"Undiagnosed joint pain >4 weeks \u2014 features atypical for OA"},{"type":"cb","id":"xrk_p3_2","label":"Known osteoarthritis with significant functional impairment, requesting orthopaedic assessment for surgery and no x-ray in last 6 months","shortLabel":"OA with significant functional impairment \u2014 requesting orthopaedic assessment"},{"type":"cb","id":"xrk_p3_3","label":"Pain in previous arthroplasty","shortLabel":"Pain in previous arthroplasty"},{"type":"cb","id":"xrk_p3_4","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent x-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)"}]}],"guidance":"Select the anatomical site being requested, then complete the clinical indicators. Osteoarthritis is typically a clinical diagnosis \u2014 X-ray is not routinely needed. X-rays to assist diagnosis are reserved for persisting joint pain with features atypical for osteoarthritis.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=20715.htm","guidanceNarrative":"Osteoarthritis is typically a clinical diagnosis and X-ray is not routinely needed to make the diagnosis. Imaging is not required for effective non-surgical management of osteoarthritis. There is generally poor correlation between symptoms and X-ray changes. Always request weight-bearing views of knees especially if considering referral for orthopaedic assessment as they give a more accurate picture of joint space narrowing.","alternativeManagement":"Acute gout \u2014 see local Gout HealthPathway.","notFundedDetail":"Follow-up of suspected or known osteoarthritis unless red flags develop or patient now meets local clinical criteria for surgery. Osgood-Schlatter disease \u2014 history and physical examination are usually sufficient. Bursitis. Sinding Larsen Johansson disease (patellar tendonitis). Patellofemoral pain syndrome including chondromalacia patella.","outOfCriteriaNote":"Not routinely funded for: follow-up of suspected/known OA unless red flags develop or patient meets surgical criteria; Osgood-Schlatter disease; bursitis; Sinding Larsen Johansson disease; patellofemoral pain syndrome.","footnotes":"*1 Clinical features atypical for osteoarthritis: patient younger than 45; recent trauma; prominent signs of inflammation (tender swelling, redness, warmth, early morning stiffness for more than 30 minutes); significant nocturnal pain or pain at rest; weight loss or systemic symptoms; inability to weight bear.","safetyQuestions":[]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('xr_pelvis_hip', 'X-Ray — Pelvis / Hip', 'X-Ray', 'multisite', 'adult', '{"examId":"xr","examTitle":"X-Ray","siteLabel":"Pelvis / Hip","inlineGuidance":"An AP Pelvis and lateral of the affected hip will reveal any gross abnormality of the opposite hip as well.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","items":[{"type":"cb","id":"xrph_emerg_1","label":"Suspected septic arthritis","shortLabel":"Suspected septic arthritis"}]},{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"xrph_p2_1","label":"Pain with red flags: persistent deep pain unrelated to activity OR unexplained night pain","shortLabel":"Red flag pain \u2014 deep/persistent or unexplained night pain"},{"type":"cb","id":"xrph_p2_2","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent x-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)"}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"xrph_p3_1","label":"Undiagnosed joint pain >4 weeks clinically inconsistent with osteoarthritis","shortLabel":"Undiagnosed joint pain >4 weeks \u2014 features atypical for OA"},{"type":"cb","id":"xrph_p3_2","label":"Known osteoarthritis with significant functional impairment, requesting orthopaedic assessment for surgery and no X-ray in last 6 months (AP Pelvis and lateral of affected hip)","shortLabel":"OA with significant functional impairment \u2014 requesting orthopaedic assessment"},{"type":"cb","id":"xrph_p3_3","label":"Pain in previous arthroplasty","shortLabel":"Pain in previous arthroplasty"},{"type":"cb","id":"xrph_p3_4","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent x-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)"}]}],"guidance":"Select the anatomical site being requested, then complete the clinical indicators. Osteoarthritis is typically a clinical diagnosis \u2014 X-ray is not routinely needed. X-rays to assist diagnosis are reserved for persisting joint pain with features atypical for osteoarthritis.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=20715.htm","guidanceNarrative":"Osteoarthritis is typically a clinical diagnosis and X-ray is not routinely needed. Imaging is not required for effective non-surgical management. There is generally poor correlation between symptoms and X-ray changes. An AP Pelvis and lateral of the affected hip will reveal any gross abnormality of the opposite hip as well.","alternativeManagement":"Acute gout.","notFundedDetail":"Clinically suspected osteoarthritis except as above. Trochanteric bursitis (Gluteus Medius tendinopathy).","outOfCriteriaNote":"Not routinely funded for: clinically suspected OA (except above); trochanteric bursitis / gluteus medius tendinopathy.","footnotes":"*1 Clinical features atypical for osteoarthritis: patient younger than 45; recent trauma; prominent signs of inflammation (tender swelling, redness, warmth, early morning stiffness for more than 30 minutes); significant nocturnal pain or pain at rest; inability to weight bear.","safetyQuestions":[]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('xr_shoulder', 'X-Ray — Shoulder', 'X-Ray', 'multisite', 'adult', '{"examId":"xr","examTitle":"X-Ray","siteLabel":"Shoulder","inlineGuidance":"Imaging is not a prerequisite for a trial of steroid injection if a clinical diagnosis has been made. Pain unresponsive to 6 weeks conservative management (physiotherapy +/- cortisone) warrants x-ray consideration.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","items":[{"type":"cb","id":"xrs_emerg_1","label":"Suspected septic arthritis","shortLabel":"Suspected septic arthritis"}]},{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"xrs_p2_1","label":"Pain with red flags: persistent deep pain unrelated to activity OR unexplained night pain","shortLabel":"Red flag pain \u2014 deep/persistent or unexplained night pain"},{"type":"cb","id":"xrs_p2_2","label":"New, unexplained bony swelling or joint deformity","shortLabel":"New unexplained bony swelling or joint deformity"},{"type":"cb","id":"xrs_p2_3","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent x-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)"}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"xrs_p3_1","label":"Undiagnosed pain after 6 weeks \u2014 imaging is not a prerequisite for a trial of steroid injection if a clinical diagnosis has been made","shortLabel":"Undiagnosed shoulder pain >6 weeks"},{"type":"cb","id":"xrs_p3_2","label":"Pain unresponsive to 6 weeks conservative management including trial of cortisone and/or physiotherapy","shortLabel":"Pain unresponsive to 6 weeks conservative management incl. cortisone/physio"},{"type":"cb","id":"xrs_p3_3","label":"Known osteoarthritis with significant functional impairment, requesting orthopaedic assessment for surgery and no x-ray in last 6 months","shortLabel":"OA with significant functional impairment \u2014 requesting orthopaedic assessment"},{"type":"cb","id":"xrs_p3_4","label":"Pain in previous arthroplasty","shortLabel":"Pain in previous arthroplasty"},{"type":"cb","id":"xrs_p3_5","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent x-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)"}]}],"guidance":"Select the anatomical site being requested, then complete the clinical indicators. Osteoarthritis is typically a clinical diagnosis \u2014 X-ray is not routinely needed. X-rays to assist diagnosis are reserved for persisting joint pain with features atypical for osteoarthritis.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=20715.htm","guidanceNarrative":"Osteoarthritis is typically a clinical diagnosis and X-ray is not routinely needed. Imaging is not required for effective non-surgical management. There is generally poor correlation between symptoms and X-ray changes. X-rays to help with diagnosis are reserved for patients with persisting joint pain and clinical features atypical for osteoarthritis. Imaging is not a pre-requisite for a trial of steroid injection when a clinical diagnosis has been made.","alternativeManagement":"Musculoskeletal x-rays requested through acute demand services \u2014 if septic arthritis is suspected refer for acute assessment without initial imaging.","notFundedDetail":"Loss of range of motion and suspected frozen shoulder unless the condition does not follow its expected natural history.","outOfCriteriaNote":"Not routinely funded for: loss of range of motion and suspected frozen shoulder unless the condition does not follow its expected natural history.","footnotes":"*1 Clinical features atypical for osteoarthritis: patient younger than 45; recent trauma; prominent signs of inflammation (tender swelling, redness, warmth, early morning stiffness for more than 30 minutes); significant nocturnal pain or pain at rest; weight loss or systemic symptoms; inability to weight bear.","safetyQuestions":[]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('xr_spine', 'X-Ray — Spine', 'X-Ray', 'multisite', 'adult', '{"examId":"xr","examTitle":"X-Ray","siteLabel":"Spine","inlineGuidance":"Approximately 90% of acute low back pain in primary care is benign and self-limiting. Between 1-4% will have a spinal fracture and <1% malignancy. Accurate screening for red flags is paramount.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","items":[{"type":"cb","id":"xrsp_emerg_1","label":"Suspected spinal infection (back pain with fever, recent infection, IV drug use, or immunosuppression) \u2014 seek acute orthopaedic advice","shortLabel":"Suspected spinal infection \u2014 seek acute orthopaedic advice"},{"type":"cb","id":"xrsp_emerg_2","label":"Suspected cauda equina syndrome (acute back pain with sphincter disturbance, gait disturbance, saddle anaesthesia, loss of bowel/bladder control, abnormal reflexes, or loss of muscle power/sensation in legs)","shortLabel":"Suspected cauda equina syndrome"}]},{"title":"Acute \u2014 within 48 hours","items":[{"type":"cb","id":"xrsp_48_1","label":"Secondary care clinician, PCRL or radiologist advises referral for acute spine X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (acute)"}]},{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"xrsp_p2_1","label":"Acute onset localised back pain and suspected osteoporotic fracture with known osteoporosis OR risk factors including prolonged current or recent use of corticosteroids","shortLabel":"Acute back pain \u2014 suspected osteoporotic fracture"},{"type":"cb","id":"xrsp_p2_2","label":"Back pain with red flags for malignant bone disease: history of cancer commonly metastasising to bone (breast, prostate, lung); unexplained weight loss >5% in 3-6 months; waking at night with pain; pain aggravated by lying down; persistent pain unrelated to mechanical activity","shortLabel":"Back pain with red flags for malignant bone disease"},{"type":"cb","id":"xrsp_p2_3","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent x-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)"}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"xrsp_p3_1","label":"Spine deformity with significant functional impairment where patient meets criteria for secondary care referral and x-ray is a pre-requisite for referral","shortLabel":"Spinal deformity \u2014 x-ray pre-requisite for secondary care referral"},{"type":"cb","id":"xrsp_p3_2","label":"Suspected ankylosing spondylitis where patient meets criteria for secondary care referral and x-ray is a pre-requisite \u2014 arrange lumbar spine and sacroiliac joints","shortLabel":"Suspected ankylosing spondylitis \u2014 x-ray pre-requisite for referral"},{"type":"cb","id":"xrsp_p3_3","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent x-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)"}]}],"guidance":"Select the anatomical site being requested, then complete the clinical indicators. Osteoarthritis is typically a clinical diagnosis \u2014 X-ray is not routinely needed. X-rays to assist diagnosis are reserved for persisting joint pain with features atypical for osteoarthritis.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=20715.htm","guidanceNarrative":"Approximately 90% of acute low back pain episodes presenting to primary care are benign self-limiting cases that do not warrant x-ray or other imaging studies. Spinal fracture and malignancy are the most common serious pathologies affecting the spine. In patients with low back pain presenting to primary care, between 1% and 4% will have a spinal fracture and in less than 1% malignancy. The low prevalence of both in primary care settings does not justify routine ancillary testing. Accurate screening tools to aid clinical decisions about when to refer for further testing +/- imaging are paramount.","alternativeManagement":"History of recent trauma \u2014 request imaging via ACC funding. Progressive neurological deficit \u2014 seek Orthopaedic advice.","notFundedDetail":"Acute (within the first six weeks) uncomplicated spine pain without red flags \u2014 see local Back Pain in Adults HealthPathway. Suspected spinal osteoarthritis or chronic spine pain without red flags (systemic illness, suspicion of malignancy, risk of infection, inflammatory disease, or osteoporosis).","outOfCriteriaNote":"Not routinely funded for: acute uncomplicated spine pain within first 6 weeks without red flags (see Back Pain in Adults HealthPathway); suspected spinal OA or chronic spine pain without red flags. History of recent trauma \u2014 request imaging via ACC funding.","footnotes":"","safetyQuestions":[]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('xr_wrist_hand', 'X-Ray — Wrist / Hand', 'X-Ray', 'multisite', 'adult', '{"examId":"xr","examTitle":"X-Ray","siteLabel":"Wrist / Hand","inlineGuidance":"X-rays reserved for persisting joint pain with features atypical for OA (patient <45; recent trauma; signs of inflammation; nocturnal pain; weight loss; inability to weight bear).","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","items":[{"type":"cb","id":"xrwh_emerg_1","label":"Suspected septic arthritis","shortLabel":"Suspected septic arthritis"}]},{"title":"P2 \u2014 Urgent, within 2 weeks","items":[{"type":"cb","id":"xrwh_p2_1","label":"Pain with red flags: persistent deep pain unrelated to activity OR unexplained night pain","shortLabel":"Red flag pain \u2014 deep/persistent or unexplained night pain"},{"type":"cb","id":"xrwh_p2_2","label":"New, unexplained bony swelling or joint deformity","shortLabel":"New unexplained bony swelling or joint deformity"},{"type":"cb","id":"xrwh_p2_3","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent x-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)"}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","items":[{"type":"cb","id":"xrwh_p3_1","label":"Undiagnosed joint pain >4 weeks with presentation not typical of osteoarthritis","shortLabel":"Undiagnosed joint pain >4 weeks \u2014 features atypical for OA"},{"type":"cb","id":"xrwh_p3_2","label":"Known osteoarthritis with significant functional impairment, requesting orthopaedic assessment for surgery and no x-ray in last 6 months","shortLabel":"OA with significant functional impairment \u2014 requesting orthopaedic assessment"},{"type":"cb","id":"xrwh_p3_3","label":"Multiple joint swelling >6 weeks and inflammatory arthritis is suspected","shortLabel":"Multiple joint swelling >6 weeks \u2014 suspected inflammatory arthritis"},{"type":"cb","id":"xrwh_p3_4","label":"Pain in previous arthroplasty","shortLabel":"Pain in previous arthroplasty"},{"type":"cb","id":"xrwh_p3_5","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent x-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)"}]}],"guidance":"Select the anatomical site being requested, then complete the clinical indicators. Osteoarthritis is typically a clinical diagnosis \u2014 X-ray is not routinely needed. X-rays to assist diagnosis are reserved for persisting joint pain with features atypical for osteoarthritis.","healthPathwaysUrl":"https://aucklandregion.communityhealthpathways.org/loginfiles/Landing.aspx?from=e39c2299b17441b693394b71ee8af7a9&page=20715.htm","guidanceNarrative":"X-rays to help with diagnosis are reserved for patients with persisting joint pain and clinical features atypical for osteoarthritis.","alternativeManagement":"Acute gout \u2014 see local Gout HealthPathway.","notFundedDetail":"Follow-up of suspected or known osteoarthritis unless red flags develop or patient now meets local clinical criteria for surgery. Recent onset pain without red flags (persistent deep pain unrelated to activity, unexplained night pain). Mild symptoms and normal examination findings.","outOfCriteriaNote":"Not routinely funded for: follow-up of suspected/known OA unless red flags develop or patient meets surgical criteria; recent onset pain without red flags; mild symptoms and normal examination findings.","footnotes":"*1 Clinical features atypical for osteoarthritis: patient younger than 45; recent trauma; prominent signs of inflammation (tender swelling, redness, warmth, early morning stiffness for more than 30 minutes); significant nocturnal pain or pain at rest; weight loss or systemic symptoms; inability to weight bear.","safetyQuestions":[]}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('mri_lumbar', 'MRI — Lumbar Spine', 'MRI', 'singlesite', 'adult', '{"groups":[{"title":"Red flags \u2014 refer for acute assessment","items":[{"type":"cb","id":"mril_emerg_1","label":"Suspected cauda equina syndrome (acute back pain with sphincter disturbance, gait disturbance, saddle anaesthesia, loss of bowel or bladder control, abnormal reflexes, or loss of muscle power or feeling in legs)","shortLabel":"Suspected cauda equina syndrome"},{"type":"cb","id":"mril_emerg_2","label":"Suspected spinal infection (back pain with fever, recent infection, IV drug use, or immunosuppression) \u2014 seek acute orthopaedic advice","shortLabel":"Suspected spinal infection"}]},{"title":"Indicative criteria (MRI not in Phase 1 national criteria)","items":[{"type":"cb","id":"mril1","label":"Progressive neurological deficit","shortLabel":"Progressive neurological deficit"},{"type":"cb","id":"mril2","label":"Suspected spinal malignancy, infection or fracture","shortLabel":"Suspected spinal malignancy, infection or fracture"},{"type":"cb","id":"mril3","label":"Radicular leg pain consistent with nerve root compression AND conservative management 6 weeks or more without adequate improvement AND being considered for surgical or interventional management","shortLabel":"Radiculopathy \u2014 failed conservative management 6+ weeks, surgical candidate"},{"type":"cb","id":"mril4","label":"Secondary care clinician, PCRL or radiologist advises MRI lumbar spine","shortLabel":"Advised by secondary care / PCRL / radiologist"}]}],"guidance":"Note: MRI is not included in Phase 1 of the National Community Referral Criteria for Imaging. This exam is deactivated pending criteria publication in a future phase. Criteria below are indicative only.","healthPathwaysUrl":"","guidanceNarrative":"","alternativeManagement":"","notFundedDetail":"","outOfCriteriaNote":"MRI Lumbar Spine is not part of Phase 1 national CRR criteria. Non-specific low back pain without red flags does not meet criteria.","footnotes":""}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('us_abdomen_paed', 'Ultrasound (Paediatric) — Abdomen (Paediatric)', 'Ultrasound', 'multisite', 'paediatric', '{"examId":"us_paed_paed_explorer","examTitle":"Ultrasound (Paediatric)","siteLabel":"Abdomen","inlineGuidance":"Acute abdominal pain or suspected appendicitis \u2014 refer for acute paediatric assessment rather than arranging community imaging.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","mandatory":false,"items":[{"type":"cb","id":"usa_p_em1","label":"Acute abdominal pain or pyloric stenosis including possible appendicitis \u2014 request acute paediatric assessment","shortLabel":"Acute abdominal pain / appendicitis \u2014 acute paediatric assessment","mandatory":false}]},{"title":"Acute \u2014 within 48 hours","mandatory":false,"items":[{"type":"cb","id":"usa_p_48_1","label":"Mass or suspected mass on examination \u2014 seek paediatric or secondary care advice and if community ultrasound recommended, arrange as acute same or next day scan","shortLabel":"Suspected abdominal mass \u2014 secondary care advice sought, US recommended","mandatory":false},{"type":"cb","id":"usa_p_48_2","label":"Suspected organomegaly on examination \u2014 seek paediatric or secondary care advice and if community ultrasound recommended, arrange acute same or next day scan","shortLabel":"Suspected organomegaly \u2014 secondary care advice sought, US recommended","mandatory":false},{"type":"cb","id":"usa_p_48_3","label":"Secondary care clinician or PCRL or radiologist advises referral for same or next day ultrasound","shortLabel":"Advised by secondary care / PCRL / radiologist (same/next day)","mandatory":false}]},{"title":"P2 \u2014 Urgent, within 2 weeks","mandatory":false,"items":[{"type":"cb","id":"usa_p_p2_1","label":"Recurrent right upper quadrant pain and suspected gallbladder pathology","shortLabel":"Recurrent RUQ pain \u2014 suspected gallbladder pathology","mandatory":false},{"type":"cb","id":"usa_p_p2_2","label":"Secondary care clinician or PCRL or radiologist advises referral for urgent ultrasound","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)","mandatory":false}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","mandatory":false,"items":[{"type":"cb","id":"usa_p_p3_1","label":"Non-acute abdominal pain (three or more bouts severe enough to affect activities, usually school attendance, over a period of not less than three months) and common causes excluded (e.g. constipation)","shortLabel":"Recurrent non-acute abdominal pain \u22653 bouts over 3+ months, common causes excluded","mandatory":false},{"type":"cb","id":"usa_p_p3_2","label":"Secondary care clinician or PCRL or radiologist advises referral for non-urgent ultrasound","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)","mandatory":false}]}],"guidance":"Paediatric Ultrasound criteria \u2014 National Primary Care Referral Criteria for Imaging, August 2025 reissue (pages 83-111). Adult criteria do not apply to patients under 16.","healthPathwaysUrl":"","guidanceNarrative":"","alternativeManagement":"","notFundedDetail":"Single episode of non-specific (generalised, central, or periumbilical) abdominal pain. Functional abdominal pain where common causes excluded.","outOfCriteriaNote":"Single episode of non-specific (generalised, central, or periumbilical) abdominal pain. Functional abdominal pain where common causes excluded.","footnotes":""}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('us_hip_paed', 'Ultrasound (Paediatric) — Hip (DDH) (Paediatric)', 'Ultrasound', 'multisite', 'paediatric', '{"examId":"us_paed_paed_explorer","examTitle":"Ultrasound (Paediatric)","siteLabel":"Hip (DDH)","inlineGuidance":"Clinical examination is first-line DDH screening. Ultrasound is appropriate from age 4 weeks to 5\u20136 months for babies with abnormal clinical findings or risk factors. After 4\u20136 months, pelvic X-ray becomes more reliable. Defer US until age 4+ weeks as accuracy improves compared to newborns.","groups":[{"title":"Acute \u2014 within 48 hours","mandatory":false,"items":[{"type":"cb","id":"ush_p_48_1","label":"Abnormal clinical hip examination (positive Barlow/Ortolani or limited abduction) in infant aged 4 weeks to 5\u20136 months","shortLabel":"Abnormal hip exam (Barlow/Ortolani positive or limited abduction) aged 4 weeks\u20136 months","mandatory":false},{"type":"cb","id":"ush_p_48_2","label":"Secondary care clinician or PCRL or radiologist advises referral for acute hip ultrasound","shortLabel":"Advised by secondary care / PCRL / radiologist (acute)","mandatory":false}]},{"title":"P2 \u2014 Urgent, within 2 weeks","mandatory":false,"items":[{"type":"cb","id":"ush_p_p2_1","label":"Infant aged 4 weeks to 5\u20136 months with one or more risk factors for DDH and normal clinical examination: breech presentation at or after 34 weeks; first-degree family history of DDH; neuromuscular condition affecting hip development","shortLabel":"Infant 4 weeks\u20136 months with DDH risk factor (breech, family history, neuromuscular) and normal exam","mandatory":false},{"type":"cb","id":"ush_p_p2_2","label":"Secondary care clinician or PCRL or radiologist advises referral for urgent hip ultrasound","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)","mandatory":false}]}],"guidance":"Paediatric Ultrasound criteria \u2014 National Primary Care Referral Criteria for Imaging, August 2025 reissue (pages 83-111). Adult criteria do not apply to patients under 16.","healthPathwaysUrl":"","guidanceNarrative":"","alternativeManagement":"","notFundedDetail":"Routine screening ultrasound for DDH in babies with no risk factors and normal clinical examination. Imaging for DDH in children older than 6 months \u2014 X-ray is preferred.","outOfCriteriaNote":"Routine screening ultrasound for DDH in babies with no risk factors and normal clinical examination. Imaging for DDH in children older than 6 months \u2014 X-ray is preferred.","footnotes":""}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('us_renal_paed', 'Ultrasound (Paediatric) — Renal (Paediatric)', 'Ultrasound', 'multisite', 'paediatric', '{"examId":"us_paed_paed_explorer","examTitle":"Ultrasound (Paediatric)","siteLabel":"Renal","inlineGuidance":"Suspected UTI in children under 2 years \u2014 ultrasound recommended after first confirmed UTI. Children over 2 years \u2014 ultrasound after recurrent UTIs.","groups":[{"title":"Acute \u2014 within 48 hours","mandatory":false,"items":[{"type":"cb","id":"usr_p_48_1","label":"Suspected acute pyelonephritis in a child not responding to antibiotics after 48 hours","shortLabel":"Pyelonephritis not responding to antibiotics at 48 hours","mandatory":false},{"type":"cb","id":"usr_p_48_2","label":"Secondary care clinician or PCRL or radiologist advises referral for acute renal ultrasound","shortLabel":"Advised by secondary care / PCRL / radiologist (acute)","mandatory":false}]},{"title":"P2 \u2014 Urgent, within 2 weeks","mandatory":false,"items":[{"type":"cb","id":"usr_p_p2_1","label":"First confirmed UTI in a child aged under 2 years","shortLabel":"First confirmed UTI aged under 2 years","mandatory":false},{"type":"cb","id":"usr_p_p2_2","label":"Atypical UTI in any child (seriously ill, poor urine flow, abdominal or bladder mass, raised creatinine, failure to respond to antibiotics within 48 hours, infection with non-E. coli organism)","shortLabel":"Atypical UTI (any age) \u2014 seriously ill, poor flow, mass, elevated creatinine, or non-E. coli","mandatory":false},{"type":"cb","id":"usr_p_p2_3","label":"Secondary care clinician or PCRL or radiologist advises referral for urgent renal ultrasound","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)","mandatory":false}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","mandatory":false,"items":[{"type":"cb","id":"usr_p_p3_1","label":"Recurrent UTI in a child aged 2 years or older (two or more confirmed UTIs)","shortLabel":"Recurrent UTI (2+) aged 2 years or older","mandatory":false},{"type":"cb","id":"usr_p_p3_2","label":"Haematuria in a child \u2014 macroscopic or persistent microscopic haematuria not explained by UTI","shortLabel":"Haematuria \u2014 macroscopic or persistent microscopic, not explained by UTI","mandatory":false},{"type":"cb","id":"usr_p_p3_3","label":"Secondary care clinician or PCRL or radiologist advises referral for non-urgent renal ultrasound","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)","mandatory":false}]}],"guidance":"Paediatric Ultrasound criteria \u2014 National Primary Care Referral Criteria for Imaging, August 2025 reissue (pages 83-111). Adult criteria do not apply to patients under 16.","healthPathwaysUrl":"","guidanceNarrative":"","alternativeManagement":"","notFundedDetail":"Routine surveillance of simple renal cysts. Screening for ADPKD without symptoms.","outOfCriteriaNote":"Routine surveillance of simple renal cysts. Screening for ADPKD without symptoms.","footnotes":""}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('us_scrotum_paed', 'Ultrasound (Paediatric) — Scrotum / Testis (Paediatric)', 'Ultrasound', 'multisite', 'paediatric', '{"examId":"us_paed_paed_explorer","examTitle":"Ultrasound (Paediatric)","siteLabel":"Scrotum / Testis","inlineGuidance":"Testicular torsion is a surgical emergency \u2014 refer immediately to ED without imaging.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","mandatory":false,"items":[{"type":"cb","id":"ussc_p_em1","label":"Suspected testicular torsion \u2014 refer immediately to ED","shortLabel":"Suspected testicular torsion \u2014 immediate ED","mandatory":false}]},{"title":"Acute \u2014 within 48 hours","mandatory":false,"items":[{"type":"cb","id":"ussc_p_48_1","label":"Acute scrotal pain or swelling where torsion has been excluded clinically or by specialist assessment","shortLabel":"Acute scrotal pain/swelling \u2014 torsion excluded","mandatory":false},{"type":"cb","id":"ussc_p_48_2","label":"Secondary care clinician or PCRL or radiologist advises referral for acute scrotal ultrasound","shortLabel":"Advised by secondary care / PCRL / radiologist (acute)","mandatory":false}]},{"title":"P2 \u2014 Urgent, within 2 weeks","mandatory":false,"items":[{"type":"cb","id":"ussc_p_p2_1","label":"Scrotal lump where it is unclear whether swelling is testicular or extra-testicular","shortLabel":"Scrotal lump \u2014 uncertain testicular vs extra-testicular","mandatory":false},{"type":"cb","id":"ussc_p_p2_2","label":"Secondary care clinician or PCRL or radiologist advises referral for urgent scrotal ultrasound","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)","mandatory":false}]}],"guidance":"Paediatric Ultrasound criteria \u2014 National Primary Care Referral Criteria for Imaging, August 2025 reissue (pages 83-111). Adult criteria do not apply to patients under 16.","healthPathwaysUrl":"","guidanceNarrative":"","alternativeManagement":"","notFundedDetail":"Uncomplicated epididymo-orchitis in older children with no diagnostic uncertainty.","outOfCriteriaNote":"Uncomplicated epididymo-orchitis in older children with no diagnostic uncertainty.","footnotes":""}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('us_soft_tissue_paed', 'Ultrasound (Paediatric) — Soft Tissue (Paediatric)', 'Ultrasound', 'multisite', 'paediatric', '{"examId":"us_paed_paed_explorer","examTitle":"Ultrasound (Paediatric)","siteLabel":"Soft Tissue","inlineGuidance":"Soft tissue sarcomas can occur in children and may be slow-growing and painless. Do not be reassured by absence of pain.","groups":[{"title":"P2 \u2014 Urgent, within 2 weeks","mandatory":false,"items":[{"type":"cb","id":"usst_p_p2_1","label":"New lump on trunk or limbs with any concerning features: deep to fascia, fixed, hard, or irregular of any size; larger than 5cm; rapidly changing; painful; recurring after previous excision","shortLabel":"New trunk/limb lump with concerning features (deep/fixed/large/rapid/recurrent)","mandatory":false},{"type":"cb","id":"usst_p_p2_2","label":"Secondary care clinician or PCRL or radiologist advises referral for urgent ultrasound","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)","mandatory":false}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","mandatory":false,"items":[{"type":"cb","id":"usst_p_p3_1","label":"Soft tissue mass without suspicious features \u2014 superficial, mobile, smaller than 5cm, no rapid change","shortLabel":"Soft tissue mass \u2014 superficial, mobile, <5cm, no suspicious features","mandatory":false},{"type":"cb","id":"usst_p_p3_2","label":"Secondary care clinician or PCRL or radiologist advises referral for non-urgent ultrasound","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)","mandatory":false}]}],"guidance":"Paediatric Ultrasound criteria \u2014 National Primary Care Referral Criteria for Imaging, August 2025 reissue (pages 83-111). Adult criteria do not apply to patients under 16.","healthPathwaysUrl":"","guidanceNarrative":"","alternativeManagement":"","notFundedDetail":"Soft tissue mass with characteristic appearance of lipoma, ganglion, or cyst with no concerning features.","outOfCriteriaNote":"Soft tissue mass with characteristic appearance of lipoma, ganglion, or cyst with no concerning features.","footnotes":""}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('xr_abdomen_paed', 'X-Ray (Paediatric) — Abdomen (Paediatric)', 'X-Ray', 'multisite', 'paediatric', '{"examId":"xr_paed_paed_explorer","examTitle":"X-Ray (Paediatric)","siteLabel":"Abdomen","inlineGuidance":"Most ingested foreign bodies are low risk and can be managed without imaging. X-rays when required should include neck, chest, and abdomen with lateral as well as frontal views of neck and chest.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","mandatory":false,"items":[{"type":"cb","id":"xra_p_em1","label":"Foreign body ingestion with: suspected oesophageal obstruction (drooling or reluctance to swallow); known or suspected disc/button battery ingestion; multiple magnets ingested; large object more than 5cm long or 2cm wide","shortLabel":"Foreign body ingestion with red flags (battery, magnet, large object, or oesophageal obstruction)","mandatory":false},{"type":"cb","id":"xra_p_em2","label":"Acute abdomen","shortLabel":"Acute abdomen","mandatory":false}]},{"title":"Acute \u2014 within 48 hours","mandatory":false,"items":[{"type":"cb","id":"xra_p_48_1","label":"Suspected ingestion of foreign body, type unclear, child asymptomatic, no red flags, and acute X-ray advised by secondary care specialist or PCRL","shortLabel":"Suspected foreign body ingestion \u2014 asymptomatic, no red flags, X-ray advised by secondary care","mandatory":false},{"type":"cb","id":"xra_p_48_2","label":"Secondary care clinician, PCRL or radiologist advises referral for same or next day X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (same/next day)","mandatory":false}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","mandatory":false,"items":[{"type":"cb","id":"xra_p_p3_1","label":"Suspected constipation refractory to initial management recommended in the local Constipation in Children HealthPathway","shortLabel":"Constipation refractory to initial management (per Constipation in Children HealthPathway)","mandatory":false},{"type":"cb","id":"xra_p_p3_2","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)","mandatory":false}]}],"guidance":"Paediatric X-Ray criteria \u2014 National Primary Care Referral Criteria for Imaging, August 2025 reissue (pages 83-111). Adult criteria do not apply to patients under 16.","healthPathwaysUrl":"","guidanceNarrative":"","alternativeManagement":"","notFundedDetail":"Abdominal pain other than suspected constipation refractory to initial management. Single episode of vomiting without red flags.","outOfCriteriaNote":"Abdominal pain other than suspected constipation refractory to initial management. Single episode of vomiting without red flags.","footnotes":""}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('xr_chest_paed', 'X-Ray (Paediatric) — Chest (Paediatric)', 'X-Ray', 'multisite', 'paediatric', '{"examId":"xr_paed_paed_explorer","examTitle":"X-Ray (Paediatric)","siteLabel":"Chest","inlineGuidance":"Chest X-ray is rarely required in suspected community-acquired pneumonia. Consider if: diagnostic uncertainty or atypical presentation; not making expected clinical progress; recurrent pneumonia symptoms suggesting underlying respiratory disease.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","mandatory":false,"items":[{"type":"cb","id":"xrc_p_em1","label":"Respiratory distress \u2014 tachycardia, tachypnoea, stridor","shortLabel":"Respiratory distress \u2014 tachycardia, tachypnoea, stridor","mandatory":false},{"type":"cb","id":"xrc_p_em2","label":"Breathing difficulties and SpO2 92% or lower","shortLabel":"SpO2 \u226492%","mandatory":false},{"type":"cb","id":"xrc_p_em3","label":"Acute severe asthma","shortLabel":"Acute severe asthma","mandatory":false},{"type":"cb","id":"xrc_p_em4","label":"Suspected inhaled foreign body","shortLabel":"Suspected inhaled foreign body","mandatory":false}]},{"title":"Acute \u2014 within 24 hours","mandatory":false,"items":[{"type":"cb","id":"xrc_p_24_1","label":"Suspected community acquired pneumonia with diagnostic uncertainty, atypical presentation, not making expected clinical progress, or recurrent pneumonia symptoms suggesting underlying respiratory disease","shortLabel":"Suspected CAP \u2014 diagnostic uncertainty, atypical, poor progress, or recurrent","mandatory":false},{"type":"cb","id":"xrc_p_24_2","label":"Secondary care clinician, PCRL or radiologist advises referral for same or next day X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (same/next day)","mandatory":false}]},{"title":"P2 \u2014 Urgent, within 2 weeks","mandatory":false,"items":[{"type":"cb","id":"xrc_p_p2_1","label":"Persistent moist or loose cough persisting for more than 4 weeks and subsequent trial of two weeks of antibiotics","shortLabel":"Persistent moist/loose cough >4 weeks AND 2-week antibiotic trial completed","mandatory":false},{"type":"cb","id":"xrc_p_p2_2","label":"Recurrent clinically diagnosed pneumonia \u2014 3 or more separate infections within 6 months","shortLabel":"Recurrent pneumonia \u2014 3+ separate infections within 6 months","mandatory":false},{"type":"cb","id":"xrc_p_p2_3","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)","mandatory":false}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","mandatory":false,"items":[{"type":"cb","id":"xrc_p_p3_1","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent chest X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)","mandatory":false}]}],"guidance":"Paediatric X-Ray criteria \u2014 National Primary Care Referral Criteria for Imaging, August 2025 reissue (pages 83-111). Adult criteria do not apply to patients under 16.","healthPathwaysUrl":"","guidanceNarrative":"","alternativeManagement":"","notFundedDetail":"Asthma \u2014 chest X-ray is not typically indicated for routine asthma management. Simple viral respiratory tract infection in a well child.","outOfCriteriaNote":"Asthma \u2014 chest X-ray is not typically indicated for routine asthma management. Simple viral respiratory tract infection in a well child.","footnotes":""}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('xr_elbow_paed', 'X-Ray (Paediatric) — Elbow (Paediatric)', 'X-Ray', 'multisite', 'paediatric', '{"examId":"xr_paed_paed_explorer","examTitle":"X-Ray (Paediatric)","siteLabel":"Elbow","inlineGuidance":"Red flags for septic arthritis or osteomyelitis: single painful or swollen limb; night waking with pain; unable to move limb normally; unwell with fever without obvious cause; skin infection slow to resolve especially over a joint.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","mandatory":false,"items":[{"type":"cb","id":"xre_p_em1","label":"Suspected septic arthritis \u2014 red flags: single painful/swollen limb; night waking with pain; unable to move limb normally; fever without obvious cause; skin infection over joint","shortLabel":"Suspected septic arthritis \u2014 red flags present","mandatory":false}]},{"title":"P2 \u2014 Urgent, within 2 weeks","mandatory":false,"items":[{"type":"cb","id":"xre_p_p2_1","label":"Undiagnosed persistent (one week or more) bone or joint pain with pain at rest or night-waking with pain","shortLabel":"Undiagnosed bone/joint pain \u22651 week with rest pain or night waking","mandatory":false},{"type":"cb","id":"xre_p_p2_2","label":"Unexplained new bony swelling or joint deformity","shortLabel":"Unexplained new bony swelling or joint deformity","mandatory":false},{"type":"cb","id":"xre_p_p2_3","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)","mandatory":false}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","mandatory":false,"items":[{"type":"cb","id":"xre_p_p3_1","label":"Persistent unexplained joint or bone pain for more than four weeks","shortLabel":"Unexplained joint/bone pain >4 weeks","mandatory":false},{"type":"cb","id":"xre_p_p3_2","label":"Pain and joint swelling with suspected inflammatory arthritis and community X-ray recommended by secondary care or PCRL","shortLabel":"Suspected inflammatory arthritis \u2014 X-ray recommended by secondary care","mandatory":false},{"type":"cb","id":"xre_p_p3_3","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)","mandatory":false}]}],"guidance":"Paediatric X-Ray criteria \u2014 National Primary Care Referral Criteria for Imaging, August 2025 reissue (pages 83-111). Adult criteria do not apply to patients under 16.","healthPathwaysUrl":"","guidanceNarrative":"","alternativeManagement":"","notFundedDetail":"Pulled elbow (radial head subluxation) \u2014 diagnosed and treated clinically without imaging in most cases.","outOfCriteriaNote":"Pulled elbow (radial head subluxation) \u2014 diagnosed and treated clinically without imaging in most cases.","footnotes":""}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('xr_feet_paed', 'X-Ray (Paediatric) — Feet (Paediatric)', 'X-Ray', 'multisite', 'paediatric', '{"examId":"xr_paed_paed_explorer","examTitle":"X-Ray (Paediatric)","siteLabel":"Feet","inlineGuidance":"Flat feet are common and normal in young children. X-ray is not indicated for flat feet unless symptomatic and refractory to conservative management.","groups":[{"title":"P2 \u2014 Urgent, within 2 weeks","mandatory":false,"items":[{"type":"cb","id":"xrf_p_p2_1","label":"Undiagnosed persistent bone or joint pain for one week or more with pain at rest or night-waking with pain","shortLabel":"Undiagnosed bone/joint pain \u22651 week with rest pain or night waking","mandatory":false},{"type":"cb","id":"xrf_p_p2_2","label":"Unexplained new bony swelling or joint deformity","shortLabel":"Unexplained new bony swelling or joint deformity","mandatory":false},{"type":"cb","id":"xrf_p_p2_3","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)","mandatory":false}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","mandatory":false,"items":[{"type":"cb","id":"xrf_p_p3_1","label":"Painful flat feet refractory to conservative management (orthotics, physiotherapy)","shortLabel":"Painful flat feet refractory to conservative management","mandatory":false},{"type":"cb","id":"xrf_p_p3_2","label":"Suspected coalition (tarsal coalition) with persistent foot pain","shortLabel":"Suspected tarsal coalition \u2014 persistent foot pain","mandatory":false},{"type":"cb","id":"xrf_p_p3_3","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)","mandatory":false}]}],"guidance":"Paediatric X-Ray criteria \u2014 National Primary Care Referral Criteria for Imaging, August 2025 reissue (pages 83-111). Adult criteria do not apply to patients under 16.","healthPathwaysUrl":"","guidanceNarrative":"","alternativeManagement":"","notFundedDetail":"Flat feet (pes planus) without symptoms. Intoeing gait without pain or functional impairment.","outOfCriteriaNote":"Flat feet (pes planus) without symptoms. Intoeing gait without pain or functional impairment.","footnotes":""}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('xr_knee_paed', 'X-Ray (Paediatric) — Knee (Paediatric)', 'X-Ray', 'multisite', 'paediatric', '{"examId":"xr_paed_paed_explorer","examTitle":"X-Ray (Paediatric)","siteLabel":"Knee","inlineGuidance":"All children with knee pain need exclusion of hip pathology. If no knee pathology on examination, arrange hip X-ray with AP pelvis and frog lateral view.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","mandatory":false,"items":[{"type":"cb","id":"xrk_p_em1","label":"Suspected septic arthritis","shortLabel":"Suspected septic arthritis","mandatory":false}]},{"title":"P2 \u2014 Urgent, within 2 weeks","mandatory":false,"items":[{"type":"cb","id":"xrk_p_p2_1","label":"Undiagnosed persistent knee pain for one week or more with pain at rest or waking at night with pain","shortLabel":"Undiagnosed knee pain \u22651 week with rest pain or night waking","mandatory":false},{"type":"cb","id":"xrk_p_p2_2","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)","mandatory":false}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","mandatory":false,"items":[{"type":"cb","id":"xrk_p_p3_1","label":"Suspected osteochondritis dissecans \u2014 joint pain typically exacerbated by activity, with or without locking or giving way, joint swelling, or reduced range of motion","shortLabel":"Suspected osteochondritis dissecans \u2014 activity-related knee pain with locking/swelling/ROM loss","mandatory":false},{"type":"cb","id":"xrk_p_p3_2","label":"Knee pain persisting for more than two weeks exacerbated by activity, including suspected apophysitis","shortLabel":"Knee pain >2 weeks, activity-related (incl. suspected apophysitis)","mandatory":false},{"type":"cb","id":"xrk_p_p3_3","label":"Unexplained new bony swelling","shortLabel":"Unexplained new bony swelling","mandatory":false},{"type":"cb","id":"xrk_p_p3_4","label":"Clinically and biochemically suspected metabolic bone disease affecting knees (e.g. rickets, scurvy)","shortLabel":"Suspected metabolic bone disease (rickets, scurvy)","mandatory":false},{"type":"cb","id":"xrk_p_p3_5","label":"Bow leg (genu varum) with concern for pathological cause in child older than 2.5 years, with unilateral deformity or symptoms","shortLabel":"Pathological bow leg \u2014 child >2.5 years, unilateral or symptomatic","mandatory":false},{"type":"cb","id":"xrk_p_p3_6","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)","mandatory":false}]}],"guidance":"Paediatric X-Ray criteria \u2014 National Primary Care Referral Criteria for Imaging, August 2025 reissue (pages 83-111). Adult criteria do not apply to patients under 16.","healthPathwaysUrl":"","guidanceNarrative":"","alternativeManagement":"","notFundedDetail":"Knock knees (genu valgum) without pathological cause in child under 2.5 years. Osgood-Schlatter disease \u2014 usually clinical diagnosis.","outOfCriteriaNote":"Knock knees (genu valgum) without pathological cause in child under 2.5 years. Osgood-Schlatter disease \u2014 usually clinical diagnosis.","footnotes":""}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('xr_pelvis_hip_paed', 'X-Ray (Paediatric) — Pelvis / Hip (Paediatric)', 'X-Ray', 'multisite', 'paediatric', '{"examId":"xr_paed_paed_explorer","examTitle":"X-Ray (Paediatric)","siteLabel":"Pelvis / Hip","inlineGuidance":"X-ray of the pelvis becomes the preferred investigation for DDH after age 4\u20136 months when ossification obscures ultrasound landmarks. Perthes disease and slipped upper femoral epiphysis (SUFE) should be considered in children with hip or knee pain.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","mandatory":false,"items":[{"type":"cb","id":"xrph_p_em1","label":"Suspected septic arthritis of the hip","shortLabel":"Suspected septic arthritis of hip","mandatory":false},{"type":"cb","id":"xrph_p_em2","label":"Suspected slipped upper femoral epiphysis (SUFE) \u2014 acute severe hip pain in overweight adolescent, inability to weight bear","shortLabel":"Suspected SUFE \u2014 acute hip pain in overweight adolescent, unable to weight bear","mandatory":false}]},{"title":"P2 \u2014 Urgent, within 2 weeks","mandatory":false,"items":[{"type":"cb","id":"xrph_p_p2_1","label":"Suspected DDH in child aged 5\u20136 months or older with abnormal hip examination or failed ultrasound screening","shortLabel":"Suspected DDH aged 5\u20136 months+ with abnormal exam or failed US screening","mandatory":false},{"type":"cb","id":"xrph_p_p2_2","label":"Hip or knee pain in child with limp, suspected Perthes disease","shortLabel":"Hip/knee pain with limp \u2014 suspected Perthes disease","mandatory":false},{"type":"cb","id":"xrph_p_p2_3","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)","mandatory":false}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","mandatory":false,"items":[{"type":"cb","id":"xrph_p_p3_1","label":"Hip pain in a child persisting for more than 2 weeks without a clear diagnosis","shortLabel":"Hip pain >2 weeks without clear diagnosis","mandatory":false},{"type":"cb","id":"xrph_p_p3_2","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)","mandatory":false}]}],"guidance":"Paediatric X-Ray criteria \u2014 National Primary Care Referral Criteria for Imaging, August 2025 reissue (pages 83-111). Adult criteria do not apply to patients under 16.","healthPathwaysUrl":"","guidanceNarrative":"","alternativeManagement":"","notFundedDetail":"Routine DDH screening X-ray in children with no risk factors and normal clinical examination.","outOfCriteriaNote":"Routine DDH screening X-ray in children with no risk factors and normal clinical examination.","footnotes":""}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('xr_shoulder_paed', 'X-Ray (Paediatric) — Shoulder (Paediatric)', 'X-Ray', 'multisite', 'paediatric', '{"examId":"xr_paed_paed_explorer","examTitle":"X-Ray (Paediatric)","siteLabel":"Shoulder","inlineGuidance":"Shoulder pain in children is less common than in adults. Always consider referred pain from the neck or chest.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","mandatory":false,"items":[{"type":"cb","id":"xrs_p_em1","label":"Suspected septic arthritis","shortLabel":"Suspected septic arthritis","mandatory":false}]},{"title":"P2 \u2014 Urgent, within 2 weeks","mandatory":false,"items":[{"type":"cb","id":"xrs_p_p2_1","label":"Undiagnosed persistent bone or joint pain for one week or more with pain at rest or night-waking","shortLabel":"Undiagnosed bone/joint pain \u22651 week with rest pain or night waking","mandatory":false},{"type":"cb","id":"xrs_p_p2_2","label":"Unexplained new bony swelling or joint deformity","shortLabel":"Unexplained new bony swelling or joint deformity","mandatory":false},{"type":"cb","id":"xrs_p_p2_3","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)","mandatory":false}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","mandatory":false,"items":[{"type":"cb","id":"xrs_p_p3_1","label":"Persistent unexplained joint or bone pain for more than four weeks","shortLabel":"Unexplained joint/bone pain >4 weeks","mandatory":false},{"type":"cb","id":"xrs_p_p3_2","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)","mandatory":false}]}],"guidance":"Paediatric X-Ray criteria \u2014 National Primary Care Referral Criteria for Imaging, August 2025 reissue (pages 83-111). Adult criteria do not apply to patients under 16.","healthPathwaysUrl":"","guidanceNarrative":"","alternativeManagement":"","notFundedDetail":"","outOfCriteriaNote":"","footnotes":""}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('xr_spine_paed', 'X-Ray (Paediatric) — Spine (Paediatric)', 'X-Ray', 'multisite', 'paediatric', '{"examId":"xr_paed_paed_explorer","examTitle":"X-Ray (Paediatric)","siteLabel":"Spine","inlineGuidance":"Scoliosis \u2014 X-ray recommended prior to secondary care referral. Consider left thoracic curves and rapidly progressing curves as higher priority.","groups":[{"title":"P3 \u2014 Non-deferrable, within 6 weeks","mandatory":false,"items":[{"type":"cb","id":"xrsp_p_p3_1","label":"Spinal deformity with community X-ray recommended prior to referral or review in secondary care, especially where scoliosis and any of: severe pain; clinically rapidly progressing curves; left thoracic curves; significant curves or significant rib humps","shortLabel":"Scoliosis or spinal deformity \u2014 X-ray recommended prior to secondary care referral","mandatory":false},{"type":"cb","id":"xrsp_p_p3_2","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent spine X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)","mandatory":false}]}],"guidance":"Paediatric X-Ray criteria \u2014 National Primary Care Referral Criteria for Imaging, August 2025 reissue (pages 83-111). Adult criteria do not apply to patients under 16.","healthPathwaysUrl":"","guidanceNarrative":"","alternativeManagement":"","notFundedDetail":"Simple isolated sacral dimples or pits without red flags \u2014 imaging not indicated.","outOfCriteriaNote":"Simple isolated sacral dimples or pits without red flags \u2014 imaging not indicated.","footnotes":""}', '2026-04-03T00:44:22.708919Z', 'migration');
INSERT INTO criteria (id, title, modality, type, population, data, updated_at, updated_by) VALUES ('xr_wrist_hand_paed', 'X-Ray (Paediatric) — Wrist / Hand (Paediatric)', 'X-Ray', 'multisite', 'paediatric', '{"examId":"xr_paed_paed_explorer","examTitle":"X-Ray (Paediatric)","siteLabel":"Wrist / Hand","inlineGuidance":"Bone age assessment is a common paediatric request \u2014 only funded if recommended by a paediatric or secondary care specialist.","groups":[{"title":"Refer for acute assessment \u2014 without initial imaging","mandatory":false,"items":[{"type":"cb","id":"xrwh_p_em1","label":"Suspected septic arthritis","shortLabel":"Suspected septic arthritis","mandatory":false}]},{"title":"P2 \u2014 Urgent, within 2 weeks","mandatory":false,"items":[{"type":"cb","id":"xrwh_p_p2_1","label":"Undiagnosed persistent bone or joint pain for one week or more with pain at rest or night-waking","shortLabel":"Undiagnosed bone/joint pain \u22651 week with rest pain or night waking","mandatory":false},{"type":"cb","id":"xrwh_p_p2_2","label":"Unexplained new bony swelling or joint deformity","shortLabel":"Unexplained new bony swelling or joint deformity","mandatory":false},{"type":"cb","id":"xrwh_p_p2_3","label":"Secondary care clinician, PCRL or radiologist advises referral for urgent X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (urgent)","mandatory":false}]},{"title":"P3 \u2014 Non-deferrable, within 6 weeks","mandatory":false,"items":[{"type":"cb","id":"xrwh_p_p3_1","label":"Persistent unexplained joint or bone pain for more than four weeks","shortLabel":"Unexplained joint/bone pain >4 weeks","mandatory":false},{"type":"cb","id":"xrwh_p_p3_2","label":"Bone age X-ray recommended by paediatric or secondary care specialist","shortLabel":"Bone age X-ray \u2014 specialist recommended","mandatory":false},{"type":"cb","id":"xrwh_p_p3_3","label":"Secondary care clinician, PCRL or radiologist advises referral for non-urgent X-ray","shortLabel":"Advised by secondary care / PCRL / radiologist (non-urgent)","mandatory":false}]}],"guidance":"Paediatric X-Ray criteria \u2014 National Primary Care Referral Criteria for Imaging, August 2025 reissue (pages 83-111). Adult criteria do not apply to patients under 16.","healthPathwaysUrl":"","guidanceNarrative":"","alternativeManagement":"","notFundedDetail":"Routine bone age X-ray without specialist recommendation.","outOfCriteriaNote":"Routine bone age X-ray without specialist recommendation.","footnotes":""}', '2026-04-03T00:44:22.708919Z', 'migration');
